const TIERS=[{id:'t1',label:'Tier 1 — Strong Evidence',badge:'Proven Effective',bg:'var(--t1bg)',tx:'var(--t1tx)',desc:'Backed by multiple large clinical trials and meta-analyses. Consistent, replicated results across independent research groups.'},{id:'t2',label:'Tier 2 — Promising / Situational',badge:'Promising',bg:'var(--t2bg)',tx:'var(--t2tx)',desc:'Supported by clinical trials but evidence is limited to specific populations, conditions, or dosages. May not benefit everyone.'},{id:'t3',label:'Tier 3 — Unproven',badge:'Unproven',bg:'var(--t3bg)',tx:'var(--t3tx)',desc:'Limited or conflicting human data. Marketing claims often exceed what the research actually shows. Approach with skepticism.'},{id:'t4',label:'Tier 4 — Risky / Avoid',badge:'Risky',bg:'var(--t4bg)',tx:'var(--t4tx)',desc:'Documented safety risks including organ damage, drug interactions, or death. Regulatory warnings issued. Do not use.'}];
const TM={};TIERS.forEach(t=>TM[t.id]=t);
const EL=['','Insufficient','Limited','Moderate','Strong','Conclusive'];
const SL=['','Dangerous','High risk','Caution advised','Good','Excellent'];

const MEDS={warfarin:{label:'Warfarin / Blood thinners',avoid:['Vitamin K2 (MK-7)',"St. John's Wort",'Ginkgo biloba'],caution:['Omega-3 (EPA/DHA)','Curcumin (bioavailable form)','Ginger (Zingiber officinale)','NAC (N-Acetyl Cysteine)'],extra:[],note:'Vitamin K2 directly antagonises warfarin. Omega-3 and ginger also have anticoagulant effects at high doses. Always inform your anticoagulation clinic before any supplement changes.'},ssri:{label:'SSRIs / SNRIs (antidepressants)',avoid:['5-HTP',"St. John's Wort"],caution:['Saffron (Crocus sativus)','Omega-3 (EPA/DHA)'],extra:[],note:'Serotonin syndrome risk — never combine serotonergic supplements with SSRIs or SNRIs without medical supervision.'},maoi:{label:'MAOIs',avoid:['5-HTP',"St. John's Wort",'Panax ginseng','Caffeine'],caution:['Saffron (Crocus sativus)','Taurine'],extra:[],note:'MAOIs have severe interactions — risk of hypertensive crisis. Consult your prescriber before using any supplement.'},statin:{label:'Statins (cholesterol)',avoid:[],caution:['Berberine','Niacin (Vitamin B3)'],extra:['CoQ10 (Ubiquinol)'],note:'Statins deplete CoQ10 — ubiquinol supplementation is clinically supported and recommended. Berberine has additive statin-like effects; monitor liver enzymes.'},metformin:{label:'Metformin',avoid:[],caution:['Berberine'],extra:['Vitamin B12'],note:'Metformin depletes vitamin B12 — supplementation with regular monitoring is clinically indicated. Berberine has additive glucose-lowering effects.'},thyroid:{label:'Levothyroxine / Thyroid meds',avoid:[],caution:['Iodine','Selenium','Iron','Calcium','Magnesium'],extra:[],note:'Many supplements interfere with levothyroxine absorption — take thyroid medication at least 4 hours apart from all supplements.'},ppi:{label:'PPIs (omeprazole, lansoprazole)',avoid:[],caution:['Magnesium'],extra:['Vitamin B12'],note:'Long-term PPIs deplete both magnesium and B12 — both should be monitored and supplemented as indicated.'},ocp:{label:'Oral contraceptive pill',avoid:["St. John's Wort"],caution:['Saffron (Crocus sativus)'],extra:['Folate (5-MTHF)','Vitamin B6 (P5P)'],note:"St. John's Wort significantly reduces OCP efficacy through CYP3A4 induction — contraception failure risk."},bp:{label:'Blood pressure medication',avoid:[],caution:['Berberine','Olive leaf extract','CoQ10 (Ubiquinol)','Taurine','Dietary Nitrate / Beetroot'],extra:[],note:'Several supplements lower blood pressure — additive hypotension risk when combined with antihypertensives.'},antibiotic:{label:'Antibiotics',avoid:[],caution:['Iron','Calcium','Magnesium','Zinc'],extra:['Probiotics'],note:'Take all mineral supplements ≥2 hours away from antibiotics to avoid absorption interference. Probiotics recommended during and after the course.'},diabetes:{label:'Diabetes meds (insulin / sulfonylurea)',avoid:[],caution:['Berberine','Alpha-Lipoic Acid (ALA)','Chromium picolinate'],extra:[],note:'Several supplements significantly lower blood glucose — hypoglycemia risk when combined with diabetes medications.'},chemo:{label:'Chemotherapy',avoid:["St. John's Wort"],caution:['NAC (N-Acetyl Cysteine)','Curcumin (bioavailable form)','Omega-3 (EPA/DHA)'],extra:[],note:'Antioxidant supplements may interfere with chemotherapy efficacy. Consult your oncologist before any supplementation.'}};

const RL=['','Minimal','Limited','Moderate','Strong','Extensive'];
const OL=['','8+ weeks','4–8 weeks','1–4 weeks','Hours–days','Immediate'];
const CL=['','Poor value','Expensive','Moderate','Affordable','Excellent'];
const DL=['','Severe risk','Significant','Moderate','Minor','None known'];

const OL_SHORT=['','8+ weeks','4-8 weeks','1-4 weeks','Hours to days','Minutes'];

const S=[
{t:'t1',n:'Creatine monohydrate',tag:'Performance · Cognition',e:5,s:5,r:5,o:3,c:5,d:5,desc:'One of the most studied supplements in the world. Over 49 large reviews confirm it boosts strength, power, and brain function. A 2024 study also found it improves working memory in healthy adults. NIH considers it safe for long-term use with no serious side effects reported across decades of research. Affordable and widely available in pure monohydrate form.',dose:'3–5 g/day, no loading or cycling needed'},
{t:'t1',n:'Omega-3 (EPA/DHA)',tag:'Cardiovascular · Inflammation',e:5,s:4,r:5,o:3,c:4,d:3,desc:'Helps protect your heart and reduce inflammation throughout the body. A 2025 review of 42 clinical trials (176,000+ people) found omega-3s significantly reduce heart attack and heart disease deaths. The NIH-funded VITAL trial showed 2,000 mg/day cut heart attacks by 28% and reduced cancer deaths by 17%. Take with a fatty meal for best absorption.',dose:'1–4 g/day EPA+DHA with a fatty meal'},
{t:'t1',n:'Vitamin D3',tag:'Bone · Immunity · Muscle',e:4,s:4,r:5,o:3,c:5,d:4,desc:'About 40% of adults worldwide are deficient. A major trial found 2,000 IU/day reduced cancer deaths by 17% and lowered risk of autoimmune diseases. Get your levels tested before supplementing. A simple blood test (25-OH-D) tells you if you need it. Supports bone density, immune function, and muscle health across all age groups.',dose:'1,000–2,000 IU/day maintenance; 4,000 IU/day to correct confirmed deficiency'},
{t:'t1',n:'Magnesium',tag:'Sleep · Cognition · Metabolic',e:4,s:5,r:4,o:3,c:5,d:3,desc:'Nearly half of Americans don\'t get enough magnesium from their diet. Strong evidence it helps with sleep quality, blood sugar control, and age-related cognitive decline. Choose glycinate for sleep and general use or L-threonate for brain health. The oxide form is poorly absorbed and mostly acts as a laxative. Very safe at recommended doses.',dose:'200–400 mg/day glycinate/L-threonate; oxide is poorly absorbed'},
{t:'t1',n:'Zinc',tag:'Immunity · Cold duration',e:4,s:4,r:5,o:4,c:4,d:4,desc:'Supports your immune system and can shorten colds significantly. A 2024 Cochrane review of 34 trials (8,500+ people) found zinc lozenges shorten colds by about 2 days when started within 24 hours. Don\'t take more than 40 mg/day long-term. Too much zinc blocks copper absorption, which can cause its own health problems.',dose:'15–30 mg/day supplementation; lozenges 80–92 mg/day for acute cold. Do not exceed 40 mg/day long-term.'},
{t:'t1',n:'Melatonin',tag:'Sleep onset · Jet lag · Circadian',e:4,s:4,r:5,o:5,c:4,d:4,desc:'Helps you fall asleep faster and reset your internal clock. A 2025-26 review of 57 studies confirms melatonin eases jet lag and supports shift workers. Short-term use is safe, but long-term nightly use hasn\'t been well studied. Most commercial products contain 10 to 30 times more than what research supports. Start with 0.3 to 1 mg.',dose:'0.3–1 mg situational use only; most commercial products are 10–30× too high'},
{t:'t1',n:'Whey protein',tag:'Muscle synthesis · Sarcopenia',e:4,s:5,r:4,o:3,c:4,d:5,desc:'Helps build lean muscle and recover faster after exercise. A 2024 analysis of 78 clinical trials (4,755 people) found whey protein significantly increases strength and lean muscle mass when combined with resistance training. It digests quickly, making it ideal right after workouts. Very safe with an excellent long-term track record.',dose:'20–40 g/serving; 1.6–2.2 g/kg/day total protein target'},
{t:'t2',n:'Ashwagandha (KSM-66)',tag:'Stress · Anxiety · Sleep',e:4,s:3,r:4,o:2,c:3,d:3,desc:'Helps lower stress and anxiety levels noticeably within weeks. Multiple 2024-2025 reviews show it significantly reduces the stress hormone cortisol. Safety data beyond 3 months is limited, and rare cases of liver injury have been reported. Best used in cycles of 8 to 12 weeks on, then 2 to 4 weeks off. Choose a standardized extract like KSM-66.',dose:'300–600 mg/day standardised extract; cycle 8–12 wks on, 2–4 off'},
{t:'t2',n:'Berberine',tag:'Metabolic · Glucose · Lipids',e:4,s:3,r:4,o:2,c:2,d:1,desc:'Helps lower blood sugar, bad cholesterol, triglycerides, and waist size. A 2025 review found berberine significantly improves these markers in people with metabolic syndrome. However, it interacts with many common medications, so always check with your doctor first. Take with meals and pair with piperine for better absorption.',dose:'500 mg × 2–3 daily with meals; pair with piperine for bioavailability'},
{t:'t2',n:'Probiotics',tag:'Gut · Immunity · RTI',e:3,s:4,r:4,o:3,c:3,d:4,desc:'Supports gut health and can reduce your risk of getting sick. A 2025 analysis found the B. animalis strain reduced respiratory infections by 21%, outperforming multi-strain blends. Benefits depend heavily on using the right strain for the right condition. Not all probiotics are the same, so choose a product backed by clinical research for your specific need.',dose:'B. animalis ≥1B CFU/day for RTI; L. rhamnosus GG for IBS-D'},
{t:'t2',n:'Boswellia serrata',tag:'Joint pain · OA',e:4,s:4,r:4,o:2,c:3,d:4,desc:'One of the best natural options for joint pain relief. A 2025 analysis ranked Boswellia as the top joint supplement out of 7 tested for knee arthritis pain. NCCIH considers it a well-tolerated herbal supplement with growing clinical evidence. Works by blocking specific inflammation pathways. Generally safe for long-term use.',dose:'300–500 mg extract (≥65% boswellic acids, ≥30% AKBA) × 2–3 daily with fat'},
{t:'t2',n:'Collagen peptides',tag:'Skin · Joint · Connective tissue',e:3,s:5,r:4,o:3,c:3,d:5,desc:'Helps improve joint comfort and skin elasticity over time. A 2024 review of 13 trials found consistent modest benefits for joint pain and skin health, but no effect on muscle strength. Collagen is not a complete protein and cannot replace whey or similar for muscle building. Generally very safe with no serious side effects reported in trials.',dose:'Skin/nail: 2.5–5 g/day; Joint: 10–15 g/day; Tendon: 15 g + 50 mg vit C pre-exercise'},
{t:'t2',n:'CoQ10 (Ubiquinol)',tag:'Heart failure · Statin users',e:3,s:4,r:4,o:3,c:3,d:4,desc:'Supports heart health and energy production in every cell. A 2024 review of 33 trials found CoQ10 reduced death risk by 36% in heart failure patients. Statin medications deplete your body\'s CoQ10 levels, making supplementation especially important if you take statins. The ubiquinol form absorbs better than ubiquinone, especially for adults over 40.',dose:'200–400 mg/day ubiquinol with a fatty meal'},
{t:'t2',n:'Rhodiola rosea',tag:'Endurance · Stress · Fatigue',e:3,s:4,r:3,o:2,c:3,d:4,desc:'Helps boost endurance and fight physical and mental fatigue. A 2025 review of 26 trials found it meaningfully improves aerobic capacity and how long you can exercise before exhaustion. NCCIH considers it generally well-tolerated for short-term use. Best used in cycles of 6 to 8 weeks on, then 2 to 4 weeks off to maintain effectiveness.',dose:'200–600 mg/day standardised extract; 6–8 wks on, 2–4 off'},
{t:'t2',n:'L-Theanine',tag:'Relaxation · Focus · Sleep',e:3,s:5,r:3,o:4,c:3,d:5,desc:'Promotes calm focus without drowsiness and pairs exceptionally well with caffeine. A 2026 review of 13 trials found 200 to 450 mg per day significantly improves sleep quality. Found naturally in green tea. One of the safest supplements available with no known side effects or dependency risk, even at high doses over extended periods.',dose:'100–200 mg alone; 200–400 mg for sleep 30–45 min before bed'},
{t:'t2',n:'Vitamin B12',tag:'Vegans · Elderly · Cognition',e:4,s:5,r:4,o:3,c:4,d:4,desc:'Essential for nerve function, energy, and red blood cell production. About 20% of adults over 60 and over 50% of strict vegans are deficient. Absorption declines with age and is reduced by acid-blocking medications, so supplements become especially important after age 50. Deficiency can cause irreversible nerve damage if left untreated.',dose:'500–1,000 mcg/day cyanocobalamin; test MMA + serum B12'},
{t:'t2',n:'Beta-Alanine',tag:'Endurance · High-intensity',e:3,s:4,r:4,o:2,c:4,d:5,desc:'Helps you push harder during high-intensity exercise by buffering acid buildup in muscles. A 2025 review of 9 trials found 4 to 6.4 g per day improved strength and power output. The tingling sensation some people feel is completely harmless. Splitting doses throughout the day reduces tingling. Requires 4 to 8 weeks of daily use to build up.',dose:'3.2–6.4 g/day in divided doses; load 4–8 wks to saturate carnosine'},
{t:'t3',n:"Lion's mane mushroom",tag:'Cognition · Neuroprotection',e:2,s:4,r:3,o:2,c:2,d:4,desc:'May support brain health and protect nerve cells over time. Small trials in people with mild cognitive decline showed improved thinking scores after 16 weeks. A 2025 trial in healthy adults was inconclusive. NCCIH says lab research is promising but human evidence is still insufficient. Benefits appear to reverse after you stop taking it.',dose:'500–3,000 mg/day fruiting body extract; benefits reversed after stopping'},
{t:'t2',n:'Curcumin (bioavailable form)',tag:'Inflammation · OA · Metabolic',e:3,s:4,r:4,o:2,c:3,d:3,desc:'A powerful natural anti-inflammatory that helps with joint pain and metabolic health. A 2025 analysis of 17 trials found all turmeric forms significantly reduced knee arthritis pain. A 2024 review of 103 trials found strong evidence it lowers inflammation markers and blood sugar. Must use a bioavailable form since plain turmeric absorbs very poorly.',dose:'250–500 mg/day curcuminoids — phytosome, liposomal, or + piperine only'},
{t:'t2',n:'Elderberry (Sambucus nigra)',tag:'Cold/Flu · Immunity',e:3,s:4,r:3,o:4,c:3,d:4,desc:'Can shorten colds and flu by 2 to 4 days when started within 48 hours of getting sick. Multiple reviews show elderberry strongly reduces cold and flu symptom severity. Rich in antioxidants and immune-supporting compounds. Best used at the first sign of illness rather than as a daily preventive. Generally well tolerated with no major safety concerns.',dose:'15 mL syrup × 4 daily for 3–5 days within 48 hrs of onset'},
{t:'t2',n:"St. John's Wort",tag:'Mild-moderate depression',e:4,s:2,r:4,o:2,c:3,d:1,desc:'Cochrane found it works as well as prescription antidepressants for mild-to-moderate depression with fewer side effects. Warning: it seriously interferes with many medications including birth control, blood thinners, HIV drugs, and chemotherapy. Medical supervision is essential. Never combine with prescription antidepressants.',dose:'900 mg/day (300 mg × 3) standardised extract (0.3% hypericin or 5% hyperforin)'},
{t:'t2',n:'Lutein + Zeaxanthin',tag:'Eye health · AMD',e:3,s:5,r:3,o:1,c:3,d:4,desc:'Protects your eyes from age-related vision loss. The landmark AREDS2 trial (4,203 people) found these eye nutrients reduced the risk of advanced macular degeneration by about 26%. Most adults on Western diets don\'t get enough from food alone. Take with a fatty meal for best absorption. Very safe with no notable side effects in long-term studies.',dose:'10 mg lutein + 2 mg zeaxanthin/day (AREDS2 formula) with a fatty meal'},
{t:'t2',n:'Iron',tag:'Deficiency · Fatigue · Anaemia',e:4,s:3,r:4,o:3,c:4,d:3,desc:'WHO reports iron deficiency affects 1.62 billion people worldwide, making it the most common nutritional deficiency. Animal-source iron absorbs 2 to 3 times better than plant-source iron. Iron is toxic if you don\'t need it. Always get a blood test for ferritin before supplementing. The bisglycinate form causes less stomach upset than other types.',dose:'30–60 mg/day ferrous bisglycinate — test ferritin first; never supplement without confirmed deficiency'},
{t:'t2',n:'Vitamin K2 (MK-7)',tag:'Bone · Vascular calcification',e:3,s:5,r:3,o:1,c:3,d:3,desc:'Helps direct calcium into your bones (where you want it) and away from your arteries (where you don\'t). The Rotterdam Study found a 57% reduction in heart disease deaths in people with the highest K2 intake. Pairs well with vitamin D3 for bone health. Do not take with warfarin or other blood thinners without medical supervision.',dose:'90–200 mcg/day MK-7, paired with Vitamin D3'},
{t:'t2',n:'Folate (5-MTHF)',tag:'Pregnancy · Methylation · Mood',e:4,s:4,r:4,o:3,c:4,d:4,desc:'The highest-rated recommendation for pregnancy and one of the most important supplements for women of childbearing age. WHO recommends 400 mcg daily for all women who could become pregnant. Birth defects of the spine and brain form by day 21 to 28, so you need to start before conception. The 5-MTHF form works for everyone regardless of genetics.',dose:'400–600 mcg/day 5-MTHF periconceptionally'},
{t:'t2',n:'Dietary Nitrate / Beetroot',tag:'Endurance · Blood pressure',e:3,s:4,r:3,o:4,c:3,d:4,desc:'Boosts exercise endurance and helps lower blood pressure naturally. A 2025 review of 20 studies (2,672 people) found beetroot meaningfully improves exercise performance. Tip: avoid antibacterial mouthwash because the bacteria in your mouth are needed to convert nitrate into its active form. Take 2 to 3 hours before exercise for best results.',dose:'400–800 mg NO₃⁻ (≈300–600 mL concentrated beetroot juice), 2–3 hrs before exercise'},
{t:'t2',n:'NAC (N-Acetyl Cysteine)',tag:'Antioxidant · OCD · Addiction',e:3,s:4,r:4,o:3,c:3,d:3,desc:'A versatile antioxidant that replenishes your body\'s master detox molecule, glutathione. Good evidence it helps as an add-on treatment for OCD, reduces addiction cravings, and improves symptoms of schizophrenia. Also commonly used during cold and flu season to support respiratory health. Well tolerated at standard doses with a long safety record.',dose:'1,200–2,400 mg/day in 2 divided doses with food'},
{t:'t2',n:'Bacopa monnieri',tag:'Memory · Cognitive speed',e:3,s:3,r:3,o:2,c:3,d:4,desc:'Helps improve memory recall and mental processing speed over time. Multiple reviews confirm these cognitive benefits, but you need at least 12 weeks of daily use to see results. Stomach upset is the most common side effect, and long-term safety beyond a few months hasn\'t been well established. Take with food to reduce digestive issues.',dose:'300–450 mg/day standardised extract (20–55% bacosides) with food'},
{t:'t2',n:'Citrulline malate',tag:'Muscular endurance · Blood flow',e:3,s:5,r:3,o:3,c:4,d:5,desc:'Helps you do more reps before exhaustion and reduces post-workout soreness. Multiple trials confirm these endurance benefits for both strength and cardio exercise. Surprisingly, it raises blood arginine levels better than arginine supplements themselves. Very safe with an excellent tolerance profile. Take about 60 minutes before exercise.',dose:'8 g citrulline malate (2:1 form) or 6–8 g pure L-citrulline, 60 min before exercise'},
{t:'t2',n:'HMB (β-Hydroxy-β-methylbutyrate)',tag:'Sarcopenia · Muscle preservation',e:3,s:4,r:3,o:3,c:3,d:4,desc:'Helps preserve lean muscle mass, especially as you age. A 2025 review of 21 trials (1,935 adults over 50) found it significantly prevents muscle loss. NIH notes the evidence is strongest for older adults and those recovering from illness. Works best when combined with resistance exercise. Allow at least 12 weeks to see meaningful results.',dose:'3 g/day (1 g × 3 with meals); allow ≥12 weeks alongside resistance exercise'},
{t:'t2',n:'Saffron (Crocus sativus)',tag:'Depression · Anxiety · Cognition',e:4,s:4,r:4,o:2,c:3,d:4,desc:'A natural option for improving mood and reducing anxiety. A 2024 review of 46 trials found saffron has strong effects on both depression and anxiety, performing as well as conventional medications in direct comparisons. Takes about 4 to 8 weeks to reach full effect. Generally well tolerated at recommended doses of 28 to 30 mg per day.',dose:'28–30 mg/day standardised saffron extract'},
{t:'t2',n:'Milk thistle (Silymarin)',tag:'Liver protection · NAFLD',e:3,s:4,r:3,o:2,c:3,d:4,desc:'Supports liver health and may help your body process fats more effectively. A 2024 review of 26 trials (2,375 patients with fatty liver disease) found milk thistle significantly improves liver function markers, insulin resistance, and blood sugar. Well tolerated with a long history of safe use. The phospholipid complex form absorbs best.',dose:'280–420 mg/day silymarin (phospholipid complex form preferred)'},
{t:'t2',n:'Acetyl-L-Carnitine (ALCAR)',tag:'Cognitive aging · Neuropathy',e:3,s:4,r:3,o:2,c:3,d:4,desc:'Supports brain function in older adults and helps relieve nerve pain. Multiple reviews confirm it significantly improves thinking ability in people with mild cognitive decline and helps with nerve pain in the hands and feet. A form of the amino acid carnitine that crosses the blood-brain barrier more effectively. Generally well tolerated at standard doses.',dose:'1,500–2,000 mg/day in 2–3 divided doses; avoid evening dosing'},
{t:'t2',n:'Myo-inositol',tag:'PCOS · Metabolic · Mental health',e:4,s:5,r:3,o:2,c:3,d:4,desc:'One of the best-supported supplements for women with PCOS. Multiple trials confirm it improves insulin sensitivity, helps restore regular ovulation, and lowers elevated male hormones. The 40:1 ratio of myo to D-chiro-inositol mirrors what your body naturally produces. Very safe with minimal side effects. Also shows promise for mental health support.',dose:'2,000–4,000 mg/day; 40:1 myo:D-chiro-inositol combination preferred for PCOS'},
{t:'t2',n:'Alpha-Lipoic Acid (ALA)',tag:'Diabetic neuropathy · Antioxidant',e:3,s:3,r:3,o:2,c:3,d:3,desc:'Helps reduce nerve pain in people with diabetic neuropathy. Multiple reviews confirm it significantly improves numbness, tingling, and burning sensations caused by nerve damage. Also acts as a powerful antioxidant that works in both water and fat. NIH warns it may lower thyroid hormone levels at doses above 1,200 mg per day. Monitor thyroid function.',dose:'600 mg/day R-ALA; racemic ALA requires higher doses'},
{t:'t2',n:'Casein protein',tag:'Overnight muscle synthesis',iN:true,e:3,s:5,r:3,o:3,c:4,d:5,desc:'Provides a slow, steady supply of protein to your muscles over about 7 hours, making it ideal for overnight recovery. A 2024 review found taking casein before bed beats whey for overnight muscle building in trained adults. Very safe with no serious side effects. Choose micellar casein for the slowest digestion and best overnight benefits.',dose:'30–40 g micellar casein 30–60 min before sleep on training days'},
{t:'t2',n:'Taurine',tag:'Cardiovascular · Metabolic · Aging',iN:true,e:3,s:4,r:3,o:3,c:4,d:4,desc:'A 2024 review of 20 trials (808 people) found taurine significantly lowers resting heart rate (-3.6 bpm), blood pressure (-4.0 mmHg), and improves heart pumping efficiency. WHO considers it conditionally essential for newborns and critically ill patients. Your body produces some taurine naturally, but levels decline with age. Very safe at recommended doses with no serious side effects reported in clinical trials.',dose:'500–3,000 mg/day in 2–3 divided doses with meals'},
{t:'t2',n:'Alpha-GPC',tag:'Cognition · Acetylcholine · Athletic',iN:true,e:3,s:3,r:3,o:2,c:2,d:3,desc:'A choline compound that supports brain function and memory. A 2025 review found it outperforms citicoline for dementia-related outcomes. A 2024 trial showed 630 mg meaningfully improved mental focus. A Korean study linked it to higher stroke risk, but the methodology was disputed and a causal connection has not been established.',dose:'300–600 mg/day for cognition; 600 mg 90 min pre-exercise for performance'},
{t:'t2',n:'Glycine',tag:'Sleep · Collagen synthesis · Metabolic',iN:true,e:3,s:5,r:3,o:3,c:5,d:5,desc:'Taking 3 g before bed significantly improves both how well you sleep and measurable sleep quality. Also an essential building block your body needs to make collagen and the antioxidant glutathione. Very safe, inexpensive, and mildly sweet tasting. One of the few supplements with virtually no side effects even at high doses over extended periods.',dose:'3 g before bed for sleep; 10–15 g/day for collagen synthesis (with vitamin C)'},
{t:'t2',n:'Tart cherry (Montmorency)',tag:'Sleep · Recovery · Inflammation',iN:true,e:3,s:5,r:3,o:2,c:2,d:5,desc:'Helps you sleep better and recover faster from intense exercise. Reviews show tart cherry meaningfully improves measurable sleep efficiency compared to placebo. Contains natural melatonin and anti-inflammatory plant compounds that also significantly reduce post-workout muscle soreness. Very safe with no notable side effects reported in studies.',dose:'480 mg concentrated extract or 240–480 mL juice twice daily; 7–10 days around intense training'},
{t:'t2',n:'Black seed oil (Nigella sativa)',tag:'Metabolic · Glucose · Lipids · BP',iN:true,e:3,s:3,r:2,o:2,c:2,d:3,desc:'Helps lower blood sugar, bad cholesterol, triglycerides, and blood pressure. Multiple 2024-2025 reviews found it significantly improves these markers in people with metabolic syndrome. The active compound thymoquinone is responsible for most benefits. Use cold-pressed oil only and do not heat it. Safety data beyond 3 months is limited.',dose:'1–3 g/day cold-pressed black seed oil; do not heat'},
{t:'t2',n:'Iodine',tag:'Thyroid function · Deficiency',iN:true,e:4,s:3,r:2,o:2,c:3,d:3,desc:'Essential for thyroid function and brain development. WHO reports iodine deficiency affects about 2 billion people worldwide and is the most common preventable cause of intellectual disability globally. However, too much iodine is also harmful to the thyroid. Never supplement without a thyroid panel blood test first, especially if you have thyroid disease.',dose:'150–220 mcg/day if deficient; test thyroid panel first; NEVER supplement without testing if thyroid disease exists'},
{t:'t2',n:'Selenium',tag:'Thyroid · Antioxidant · Immune',iN:true,e:3,s:3,r:2,o:2,c:3,d:4,desc:'Essential for thyroid function and your body\'s antioxidant defenses. A 2024 review found it reduces thyroid autoimmune markers in people who are deficient. Most people can get enough from a couple of Brazil nuts daily. Too much selenium (over 400 mcg per day) causes toxicity including hair loss, nail brittleness, and nerve damage.',dose:'55–200 mcg/day selenomethionine; test serum selenium first; do not exceed 400 mcg/day'},
{t:'t2',n:'Ginger (Zingiber officinale)',tag:'Nausea · Inflammation · Pain',iN:true,e:4,s:5,r:4,o:4,c:3,d:4,desc:'One of the best natural remedies for nausea of all types. Cochrane confirms ginger significantly reduces pregnancy nausea. A 2024 review of 12 trials also found it significantly reduces chemotherapy-related nausea. It works as an anti-inflammatory through similar pathways as ibuprofen. Very safe with a long history of use across many cultures.',dose:'1–2 g/day standardised extract (5% gingerols) for nausea; 500 mg × 2 for inflammation'},
{t:'t2',n:'Peppermint oil (enteric-coated)',tag:'IBS · Gut motility · Pain',iN:true,e:4,s:4,r:4,o:4,c:3,d:4,desc:'One of the best-supported natural treatments for IBS. A 2024 review of 12 trials found enteric-coated peppermint oil significantly improves overall IBS symptoms including pain, bloating, and urgency. Must use enteric-coated capsules because regular peppermint oil won\'t survive stomach acid. Take 30 to 60 minutes before meals for best results.',dose:'0.2–0.4 mL enteric-coated capsule × 3 daily, 30–60 min before meals'},
{t:'t2',n:'Citicoline (CDP-Choline)',tag:'Cognition · Stroke recovery · Memory',iN:true,e:3,s:4,r:2,o:2,c:2,d:4,desc:'Supports brain function and aids recovery after stroke. A 2024 review of 22 trials found it significantly improves thinking ability in people with mild cognitive decline. Better tolerated than Alpha-GPC with no identified stroke risk. Provides choline, a nutrient most people don\'t get enough of, in a form that readily reaches the brain.',dose:'250–500 mg/day; up to 1,000–2,000 mg/day in stroke recovery protocols'},
{t:'t2',n:'Palmitoylethanolamide (PEA)',tag:'Neuropathic pain · Inflammation',iN:true,e:3,s:5,r:2,o:3,c:2,d:5,desc:'A natural pain-relieving compound your body already produces in small amounts. A 2024 review of 16 trials found PEA strongly reduces nerve pain and arthritis pain. It has an excellent safety profile with no known drug interactions. Choose the ultramicronised or co-micronised form because the standard form absorbs poorly and may not be effective.',dose:'300–600 mg/day ultramicronised or co-micronised form (standard form poorly absorbed)'},
{t:'t2',n:'Riboflavin (Vitamin B2)',tag:'Migraine prevention · Energy metabolism',iN:true,e:3,s:5,r:3,o:2,c:2,d:4,desc:'Helps prevent migraines when taken daily. A 2024 Cochrane update found 400 mg per day significantly reduces migraine frequency by about 2 days per month compared to placebo. Also essential for energy metabolism in every cell. Very safe even at high doses since it is water-soluble and excess is excreted. Allow 3 to 6 months to see full benefit.',dose:'400 mg/day for migraine prevention; take with food; allow 3–6 months before assessing response'},
{t:'t3',n:'Colostrum (bovine)',tag:'Gut barrier · Immune · Recovery',iN:true,e:2,s:4,r:2,o:2,c:2,d:4,desc:'Supports immune health and gut barrier integrity. A 2024 review of 14 trials found bovine colostrum significantly reduces upper respiratory infections in athletes and strengthens the gut lining. Rich in immune antibodies and growth factors. The strongest evidence applies to athletes and people under physical stress. Generally well tolerated.',dose:'20–60 g/day bovine colostrum powder; best evidence for athletic populations'},
{t:'t2',n:'Digestive enzymes',tag:'IBS · Food intolerance · Bloating',iN:true,e:3,s:4,r:3,o:4,c:3,d:4,desc:'Helps you digest food when your body doesn\'t produce enough enzymes on its own. Strong evidence for people whose pancreas doesn\'t make enough enzymes. A 2024 trial also found benefit for general bloating and indigestion. Lactase supplements are Cochrane-supported for lactose intolerance. Choose the right enzyme type for your specific issue.',dose:'Lactase: 6,000–9,000 FCC units with dairy. Broad blend: 1 capsule with largest meal.'},
{t:'t2',n:'Niacin (Vitamin B3)',iN:true,tag:'Lipids · Skin · Energy metabolism',e:3,s:3,r:3,o:3,c:4,d:4,desc:'The niacinamide form reduces precancerous skin spots (Cochrane-confirmed) and improves skin health. The nicotinic acid or "flush" form raises good cholesterol and lowers triglycerides but requires medical monitoring due to side effects including flushing, itching, and potential liver damage. Avoid sustained-release forms at high doses due to increased liver toxicity risk. Start at low doses and increase gradually.',dose:'Niacinamide: 500 mg/day for skin. Nicotinic acid: 500–2,000 mg/day for lipids (must be supervised — liver toxicity at high doses).'},
{t:'t2',n:'Vitamin B6 (P5P)',iN:true,tag:'PMS · Pregnancy nausea · OCP support',e:3,s:3,r:3,o:2,c:4,d:4,desc:'Helps relieve PMS symptoms and pregnancy nausea. Recommended for pregnancy nausea at 10 to 25 mg three times daily. A 2024 review found it significantly improves PMS symptoms. Birth control pills deplete B6 levels, making supplementation useful for women on oral contraceptives. Never exceed 100 mg per day long-term due to nerve damage risk.',dose:'25–50 mg/day P5P for PMS/OCP support. 10–25 mg × 3 daily for NVP. NEVER exceed 100 mg/day long-term.'},
{t:'t2',n:'Choline',iN:true,tag:'Cognition · Liver · Methylation',e:3,s:4,r:3,o:2,c:4,d:4,desc:'An essential nutrient that about 90% of Americans don\'t get enough of. Your body needs it for brain signaling, cell membranes, liver function, and critical metabolic processes. Eggs and liver are the best food sources. Pregnant women need extra choline for fetal brain development. Generally safe at recommended doses with no serious side effects.',dose:'250–550 mg/day from CDP-choline, alpha-GPC, or choline bitartrate; dietary sources (eggs, liver) preferred'},
{t:'t2',n:'Olive leaf extract',iN:true,tag:'Blood pressure · Antiviral · Antioxidant',e:3,s:4,r:3,o:2,c:2,d:4,desc:'Helps lower blood pressure naturally. A 2024 review of 12 trials found olive leaf extract significantly reduces blood pressure by about 6/3 mmHg. Lab studies also confirm antiviral activity from its active compound oleuropein. Monitor your blood pressure if already on blood pressure medication, as the combined effect may cause it to drop too low.',dose:'500–1,000 mg/day standardised extract (6–19% oleuropein); monitor blood pressure if on antihypertensives'},
{t:'t2',n:'Fenugreek (Trigonella foenum-graecum)',iN:true,tag:'Testosterone · Libido · Glucose',e:3,s:4,r:2,o:2,c:2,d:4,desc:'Helps improve testosterone levels and sexual function in men. A 2024 review of 12 trials found it significantly boosts both. Also modestly lowers blood sugar levels. The Testofen brand extract has the most research behind it. Generally well tolerated, though it can cause mild digestive upset in some people. Take with food for best results.',dose:'500–600 mg/day standardised extract (50% furostanol saponins) with food'},
{t:'t2',n:'Psyllium husk (Plantago ovata)',iN:true,tag:'Cholesterol · Gut · Glucose',e:4,s:5,r:4,o:3,c:5,d:5,desc:'One of the few supplements with FDA approval for a health claim: cholesterol reduction. A 2024 review of 28 trials found it significantly lowers bad cholesterol, blood sugar, and long-term blood sugar markers. Excellent safety record and very well tolerated. Start with a low dose and drink plenty of water to prevent bloating and constipation.',dose:'5–10 g/day in divided doses with plenty of water; start low to minimise bloating'},
{t:'t3',n:'NMN / NAD+ precursors',tag:'Anti-aging / Longevity',e:2,s:3,r:2,o:1,c:1,d:4,desc:'Raises levels of NAD+, a molecule that declines with age and is linked to cellular repair. A 2024 review of 12 trials confirmed NMN successfully raises NAD+ levels in humans, but no meaningful health improvements have been observed yet. Expensive and considered experimental. Long-term safety data is lacking. Research is ongoing but results so far are disappointing.',dose:'250–900 mg/day in trials (no established optimal dose)'},
{t:'t3',n:'BCAAs (standalone)',tag:'Muscle recovery',e:2,s:5,r:2,o:4,c:3,d:5,desc:'No additional muscle-building benefit over regular complete protein (like whey) when you\'re already eating enough protein. A 2024 review confirmed that standalone BCAAs do not improve muscle growth beyond what adequate total protein provides. Only useful if your total protein intake is consistently too low. Very safe but usually unnecessary.',dose:'5–10 g peri-workout — only meaningful if total protein intake is inadequate'},
{t:'t3',n:'Glucosamine / Chondroitin',tag:'Joint pain',e:2,s:4,r:4,o:1,c:3,d:5,desc:'The major GAIT trial (1,583 people) found glucosamine was no better than placebo for joint pain. Chondroitin shows modest arthritis benefits in some people, but evidence is mixed overall. Despite being the most popular joint supplement, newer options like Boswellia and collagen type II have stronger evidence. Very safe if you choose to try it.',dose:'Glucosamine sulfate 1,500 mg/day + Chondroitin sulfate 1,200 mg/day; trial 3 months'},
{t:'t3',n:'Multivitamins (healthy adults)',tag:'General prevention',e:2,s:4,r:3,o:3,c:3,d:4,desc:'Not needed if you eat a balanced diet. The US Preventive Services Task Force (2022) found insufficient evidence that multivitamins reduce cancer, heart disease, or death risk in well-nourished adults. May be useful for people with restricted diets or confirmed nutrient gaps. Avoid mega-dose formulations that exceed 100% of daily values for any nutrient.',dose:'Standard RDA-level only. Avoid mega-dose formulations.'},
{t:'t3',n:'Valerian root',tag:'Sleep · Anxiety',e:2,s:4,r:2,o:4,c:3,d:4,desc:'A popular herbal sleep aid, but the science is underwhelming. NCCIH found that while people report sleeping better with valerian, objective sleep measurements show no actual improvement. The benefit may be placebo. Generally safe for short-term use with minimal side effects. If you want a natural sleep aid, melatonin or L-theanine have stronger evidence.',dose:'300–600 mg standardised extract (0.3–0.8% valerenic acid), 30–60 min before bed'},
{t:'t3',n:'Spirulina',tag:'Antioxidant · Lipids',e:2,s:3,r:2,o:3,c:3,d:4,desc:'A nutrient-dense algae that shows modest reductions in bad cholesterol, triglycerides, and inflammation markers. NCCIH warns of contamination risks with toxins and heavy metals, so only buy third-party tested products. Rich in protein and B vitamins. Generally safe when sourced from a reputable supplier with verified purity testing.',dose:'2–4 g/day; third-party tested products only (heavy metal contamination risk)'},
{t:'t3',n:'5-HTP',tag:'Mood · Sleep · Appetite',e:2,s:2,r:2,o:4,c:3,d:2,desc:'Your body converts it directly into serotonin, which helps with mood and sleep. Small trials show benefits for both. Warning: potentially dangerous when combined with antidepressants (SSRIs, SNRIs) or migraine medications due to risk of serotonin syndrome, a serious and potentially life-threatening condition. Use only in short courses of 6 to 8 weeks.',dose:'50–100 mg/day (short courses only, max 6–8 weeks; NEVER combine with serotonergic drugs)'},
{t:'t3',n:'Vitamin C (megadose)',tag:'Prevention / Immunity',e:2,s:3,r:4,o:3,c:4,d:5,desc:'Cochrane found high-dose vitamin C does not prevent colds in the general population, though it may shorten them by about 8%. Your body can only absorb about 200 to 400 mg at a time, so higher doses are mostly excreted. Regular athletes may benefit more, with a 50% reduction in cold risk. Doses above 1 to 2 g per day can cause kidney stones.',dose:'≤500 mg/day supplemental — doses above 1–2 g/day are primarily excreted'},
{t:'t3',n:'Resveratrol',tag:'Anti-aging / Cardiovascular',e:1,s:3,r:2,o:1,c:1,d:4,desc:'Despite years of hype, resveratrol has not delivered on its promises in human studies. Only about 1% of what you swallow actually gets absorbed, and no human trials have shown consistent benefits. Found naturally in red wine and berries, but supplement doses have unclear relevance. Consider pterostilbene as a better-absorbed alternative.',dose:'All clinical trials returned null results — no evidence-based dose can be recommended'},
{t:'t3',n:'Detox supplements',tag:'Detoxification claims',e:1,s:3,r:1,o:3,c:1,d:3,desc:'No clinical trial evidence supports "detox" benefits in healthy people. European food safety authorities rejected all detox health claims submitted by manufacturers. Your liver and kidneys already detoxify your body continuously and do not need supplement support. Save your money and focus on a balanced diet, adequate water intake, and regular exercise.',dose:'No evidence-based dose — do not use routinely'},
{t:'t3',n:'Collagen for muscle strength',tag:'Performance claim',e:1,s:5,r:1,o:3,c:3,d:5,desc:'Collagen is missing key amino acids needed for muscle building and cannot replace complete protein sources like whey or eggs. A 2024 review of 13 trials found no significant effect on muscle strength or power. While collagen has benefits for skin and joints, it should never be marketed or used as a muscle-building protein supplement.',dose:'N/A — no effective dose for muscle building'},
{t:'t3',n:'Turkesterone / Ecdysteroids',iN:true,tag:'Anabolic / Muscle building',e:1,s:4,r:2,o:2,c:1,d:4,desc:'Heavily marketed on social media as a natural muscle builder, but the science does not support the claims. Two 2024-2025 trials tested 500 mg per day for 4 weeks and found no significant differences compared to placebo in muscle mass, fat mass, or strength. The insect-based compounds don\'t appear to work the same way in humans as in insects.',dose:'Null results at 500–1,000 mg/day in human RCTs'},
{t:'t3',n:'Ginkgo biloba',iN:true,tag:'Cognitive / Dementia prevention',e:2,s:3,r:4,o:2,c:3,d:2,desc:'Despite decades of popularity, ginkgo has not proven effective for preventing cognitive decline. The major GEM trial (3,069 people, 6+ years) found no significant reduction in dementia risk. NCCIH warns it may thin the blood, so use caution with blood-thinning medications like warfarin and aspirin. Generally safe at standard doses otherwise.',dose:'120–240 mg/day standardised extract (EGb 761)'},
{t:'t3',n:'Green tea extract (EGCG)',iN:true,tag:'Weight loss / Antioxidant',e:2,s:2,r:2,o:3,c:3,d:2,desc:'Produces only modest weight loss (about 1 to 3 kg) and comes with serious liver risks. EGCG supplements are the most common herbal cause of liver damage reported to poison control centers. European food safety authorities flagged doses above 800 mg per day as dangerous. Drinking green tea is far safer than taking concentrated extracts.',dose:'≤400 mg EGCG/day with food. EFSA: ≥800 mg/day associated with hepatotoxicity.'},
{t:'t3',n:'Glutamine (standalone, healthy adults)',iN:true,tag:'Gut health / Immunity',e:2,s:4,r:2,o:3,c:3,d:5,desc:'Has real evidence for helping critically ill and hospitalized patients recover. However, your body already makes about 80 g per day on its own, so supplements add little benefit for healthy people who eat enough protein. The one exception is post-infectious irritable bowel syndrome, where 15 g per day may help restore gut lining. Very safe.',dose:'15 g/day for post-infectious IBS-D (best current application)'},
{t:'t3',n:'Panax ginseng',iN:true,tag:'Cognitive / Fatigue / Sexual health',e:2,s:3,r:2,o:2,c:3,d:2,desc:'May help with mental energy and reduce fatigue, but results are highly inconsistent across studies. Small trials show improvements in working memory and mental fatigue, yet many other trials found no benefit. NCCIH warns it interacts with many common medications including blood thinners and diabetes drugs. Check with your doctor before use.',dose:'200–400 mg/day standardised extract (minimum 4–7% ginsenosides)'},
{t:'t3',n:'Phosphatidylserine',tag:'Cognition · Memory · Cortisol',e:2,s:4,r:2,o:2,c:3,d:4,desc:'May support memory in older adults, but the evidence is thin. FDA allows a "qualified health claim" for phosphatidylserine, though this is a low bar that does not mean proven effectiveness. Shows modest memory improvements in some older adult trials, but overall clinical evidence remains limited. Safe at standard doses with no major side effects.',dose:'300 mg/day (100 mg × 3 with meals)'},
{t:'t3',n:'Astaxanthin',iN:true,tag:'Antioxidant · Skin · Recovery',e:2,s:4,r:2,o:2,c:3,d:4,desc:'One of the most potent natural antioxidants, giving salmon and shrimp their pink color. Human trials show modest improvements in skin hydration and exercise recovery. However, NCCIH notes virtually all trials are manufacturer-funded and small, raising bias concerns. Generally safe and well tolerated. Take with a fatty meal for best absorption.',dose:'4–12 mg/day from Haematococcus pluvialis algae, with a fatty meal'},
{t:'t3',n:'Quercetin',iN:true,tag:'Anti-inflammatory · Antiviral · Longevity',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A plant compound with impressive antioxidant and antiviral activity in lab studies, but poor real-world results. NCCIH notes that only about 1% is absorbed in its basic form, so the impressive lab results don\'t reliably translate to actual benefits. The phytosome form absorbs better. Human trial evidence remains weak and inconsistent overall.',dose:'500–1,000 mg/day quercetin phytosome for improved absorption; evidence base insufficient'},
{t:'t3',n:'CBD (Cannabidiol)',iN:true,tag:'Anxiety · Sleep · Pain',e:2,s:3,r:2,o:3,c:1,d:3,desc:'Only pharmaceutical-grade CBD (Epidiolex) has proven benefits, specifically for epilepsy. Anxiety and sleep claims in wellness products are not supported by rigorous trials. Retail products are frequently mislabeled, with some containing little or no actual CBD. Can interact with many medications. The effective doses used in research are far higher than typical retail products.',dose:'If used: 300–600 mg/day pharmaceutical-grade CBD for anxiety in RCTs; retail products are frequently mislabelled'},
{t:'t3',n:'Saw palmetto (Serenoa repens)',iN:true,tag:'BPH · Urinary symptoms · Prostate',e:2,s:4,r:4,o:2,c:3,d:4,desc:'Despite being one of the most popular prostate supplements, the evidence does not support it. A 2024 Cochrane review found saw palmetto is no better than placebo for improving urinary symptoms in men with enlarged prostate. Well tolerated with few side effects, but your money is better spent on options with actual proven benefits.',dose:'320 mg/day standardised extract (85–95% fatty acids); evidence does not support routine use'},
{t:'t3',n:'Lithium orotate (low-dose)',iN:true,tag:'Mood · Neuroprotection · Longevity',e:2,s:3,r:2,o:2,c:2,d:3,desc:'Different from prescription lithium, which is used at much higher doses for bipolar disorder. Small population studies suggest brain-protective effects at very low doses, but very few human trials exist. No established therapeutic dose or safety profile. Consider this entirely experimental. Do not combine with prescription lithium without medical supervision.',dose:'1–5 mg/day lithium orotate (experimental use only; no evidence-based dose established)'},
{t:'t3',n:'Pterostilbene',iN:true,tag:'Antioxidant · Anti-aging / Longevity',e:1,s:3,r:2,o:1,c:1,d:4,desc:'Related to resveratrol but far better absorbed (about 80% vs. 1%), which makes it more promising as an antioxidant supplement. Despite this absorption advantage, human trial evidence remains sparse with very few clinical studies completed. NCCIH says there is insufficient evidence to recommend it for any specific condition. Long-term safety data is limited.',dose:'50–250 mg/day (no established optimal dose; limited human safety data beyond 3 months)'},
{t:'t3',n:'Lemon balm (Melissa officinalis)',iN:true,tag:'Anxiety · Sleep · Cognitive calm',e:2,s:4,r:2,o:3,c:3,d:4,desc:'A gentle calming herb commonly consumed as tea. A 2024 review of 9 trials found it meaningfully reduces anxiety, though results varied widely between studies. NCCIH considers it generally safe for short-term use. Contains rosmarinic acid, which has natural calming properties. May also modestly improve sleep quality when taken before bed.',dose:'300–600 mg/day standardised extract (2–5% rosmarinic acid); allow 2–4 weeks for assessment'},
{t:'t3',n:'Shilajit (Mumie)',iN:true,tag:'Energy · Testosterone · Anti-aging',e:2,s:2,r:2,o:2,c:1,d:3,desc:'Small industry-funded trials show modest improvements in testosterone and fatigue, but independent research is lacking. Warning: 40% of commercial products failed heavy metal testing including lead and arsenic. Only buy NSF or USP certified products. The purified form is essential for safety. Long-term use beyond a few months has not been studied.',dose:'200–500 mg/day purified form only — buy only NSF or USP certified; heavy metal toxicity risk is not trivial'},
{t:'t3',n:'Chromium picolinate',iN:true,tag:'Insulin sensitivity · Glucose · Weight',e:2,s:3,r:2,o:2,c:3,d:3,desc:'Most Americans aren\'t deficient in chromium, which limits the usefulness of supplements. A 2024 review found only a modest blood sugar reduction in diabetics already on medication. European food safety authorities have approved no health claims. May be worth trying if you have confirmed chromium deficiency, but otherwise offers little benefit.',dose:'200–1,000 mcg/day; evidence weak in non-deficient healthy adults'},
{t:'t3',n:'Hyaluronic acid (oral)',iN:true,tag:'Joint lubrication · Skin hydration',e:2,s:5,r:2,o:2,c:3,d:5,desc:'A 2024 review of 10 trials found modest knee pain reduction and improved skin hydration from oral supplements. How well the oral form actually gets absorbed into joints and skin is less clear than the topical form. Generally considered very safe with no serious side effects reported. The low-molecular-weight form may absorb better than standard.',dose:'80–200 mg/day low-molecular-weight form (better absorbed)'},
{t:'t3',n:'GABA (standalone supplement)',iN:true,tag:'Anxiety · Sleep · Relaxation',e:2,s:4,r:2,o:4,c:3,d:4,desc:'Standard GABA supplements may not cross the blood-brain barrier in meaningful amounts, which limits their effectiveness. Some anti-anxiety effects have been reported, and a 2024 review found modest improvements in self-reported stress. The PharmaGABA form may work better. Generally safe with no serious side effects, but evidence overall is weak.',dose:'100–750 mg/day; PharmaGABA form may have better CNS effects'},
{t:'t3',n:'Boron',iN:true,tag:'Joint health · Testosterone · Bone',e:2,s:3,r:2,o:2,c:3,d:4,desc:'A trace mineral with no established daily requirement. Observational data links dietary boron to joint health, bone density, and possibly testosterone in men with low boron intake. European food safety authorities set an upper safe limit of 10 mg per day. Generally safe at low doses. Most people get some boron from fruits, nuts, and vegetables.',dose:'3–6 mg/day boron glycinate; do not exceed 10 mg/day'},
{t:'t3',n:'Agmatine sulfate',iN:true,tag:'Neuropathic pain · Mood · Athletic',e:2,s:3,r:2,o:3,c:2,d:3,desc:'Shows promise for nerve pain and mood improvement, but evidence is very early-stage. A handful of small trials show pain reduction for nerve pain and modest mood benefits. Fewer than 5 human trials exist in total, making this largely experimental. Long-term safety beyond 5 months is unclear. Not recommended as a first-line supplement.',dose:'1–2.67 g/day for neuropathic pain; safety beyond 5 months unclear'},
{t:'t3',n:'Serrapeptase',iN:true,tag:'Anti-inflammatory · Sinus · Swelling',e:1,s:3,r:2,o:3,c:3,d:4,desc:'An enzyme with strong anti-inflammatory activity in lab studies, but Cochrane found insufficient evidence for any real-world use. European food safety authorities rejected all submitted health claims. Sometimes marketed for sinus pain and post-surgical swelling. Must use enteric-coated capsules because stomach acid destroys the enzyme otherwise.',dose:'10–60 mg/day enteric-coated; evidence base too weak to recommend'},
{t:'t3',n:'Spermidine',iN:true,tag:'Autophagy · Longevity · Cognitive aging',e:2,s:4,r:2,o:1,c:1,d:4,desc:'A natural compound that triggers your body\'s cellular cleanup process called autophagy. Animal longevity data is compelling, and a 2024 pilot trial (60 adults, 12 months) showed improved cognitive scores vs. placebo. Found naturally in wheat germ, soy, and mushrooms. Human evidence is still very early-stage, and no established therapeutic dose exists yet. Generally considered safe at dietary intake levels.',dose:'1.2 mg/day in trials (wheat germ-derived spermidine); dietary sources may be sufficient'},
{t:'t3',n:'Oregano oil (Origanum vulgare)',iN:true,tag:'Antimicrobial · Gut · Antifungal',e:1,s:3,r:2,o:3,c:3,d:4,desc:'Kills bacteria and fungi effectively in lab settings, which has led to enthusiastic marketing. However, NCCIH notes human trial evidence for oral supplement use is essentially nonexistent. High concentrations can irritate the stomach lining and esophagus. Using oregano in cooking is safe and enjoyable, but taking concentrated oil supplements is not supported.',dose:'No evidence-based dose for internal supplement use; culinary use in food is safe'},
{t:'t4',n:'Kava (high-dose/extract)',tag:'Liver toxicity',e:3,s:1,r:1,o:4,c:2,d:1,desc:'Poses serious liver toxicity risks in extract form. CDC reported in April 2026 that 39% of kava exposures in 2024 had serious outcomes, with 8 deaths over 25 years. WHO issued a global liver toxicity warning. Traditional water-based kava beverages appear safer, but the concentrated supplement extracts sold commercially carry significant liver damage risk.',dose:'AVOID — solvent-extracted supplement-form kava'},
{t:'t4',n:'Tianeptine ("gas station heroin")',tag:'Opioid-like dependency',e:2,s:1,r:1,o:4,c:1,d:1,desc:'Extremely dangerous. Acts on the same brain receptors as opioids at supplement doses. Causes rapid physical dependence and opioid-like withdrawal symptoms that can require medical treatment. Not approved as a supplement in the US or EU. Often sold online as a "dietary supplement" or "nootropic" to circumvent regulations. Avoid entirely.',dose:'AVOID entirely'},
{t:'t4',n:'High-dose fat-soluble vitamins (A, E)',tag:'Excess toxicity',e:1,s:1,r:1,o:3,c:2,d:1,desc:'Taking high doses of fat-soluble vitamins is dangerous because they accumulate in your body. Cochrane found vitamin E above 400 IU per day actually increases death risk. NIH warns vitamin A above 10,000 IU per day causes liver damage and birth defects. These vitamins are easy to get from a normal diet. Never exceed recommended upper limits.',dose:'Safe upper limits: Vitamin A ≤3,000 mcg RAE/day; Vitamin E ≤400 IU/day'},
{t:'t4',n:'Aristolochic acid (in some herbal products)',tag:'Kidney cancer · Nephrotoxicity',e:1,s:1,r:1,o:3,c:1,d:1,desc:'Classified as a confirmed human carcinogen by international cancer authorities. WHO warns it causes irreversible kidney damage that progresses to bladder cancer. Found in some traditional Chinese and Ayurvedic herbal products, sometimes under names like "mu tong" or "fang ji." There is no safe dose. Always check herbal product ingredient lists carefully.',dose:'ZERO safe dose — avoid "mu tong," "fang ji," or "Aristolochia"'},
{t:'t4',n:'Ephedra analogues (synephrine)',tag:'Cardiovascular risk',e:2,s:1,r:1,o:4,c:2,d:1,desc:'Linked to over 30 serious heart events including 7 deaths in a systematic review. Ephedra was banned by the FDA in 2004 after 155 deaths, and synephrine carries similar risks. Especially dangerous when combined with caffeine or during intense exercise. Still found in some "fat burner" and pre-workout products despite the known dangers.',dose:'AVOID — especially combined with caffeine and exercise'},
{t:'t4',n:'Kratom (Mitragyna speciosa)',tag:'Opioid-like dependency',e:2,s:1,r:1,o:4,c:1,d:1,desc:'Activates opioid receptors in the brain, producing effects similar to opioid drugs. Causes physical dependence and withdrawal symptoms identical to opioid withdrawal, including nausea, insomnia, and muscle pain. Not approved for medical use by any major health authority. Sometimes marketed as a natural pain reliever, but the addiction risk is serious.',dose:'AVOID as a consumer supplement'},
{t:'t4',n:'DMAA/DMHA novel stimulant pre-workouts',tag:'Cardiovascular risk · Seizures',e:2,s:1,r:1,o:5,c:2,d:1,desc:'Dangerous stimulants that have caused deaths and serious cardiovascular events. FDA banned DMAA in 2013 after deaths linked to it, but similar compounds keep showing up in pre-workout products without being listed on the label. Can cause heart attacks, seizures, and dangerous blood pressure spikes. Only use products with NSF Certified for Sport verification.',dose:'AVOID — check NSF Certified for Sport or Informed Sport certification'},
{t:'t2',n:'Vitamin A (retinol, low-dose)',iN:true,tag:'Vision · Immunity · Skin',e:4,s:4,r:3,o:3,c:3,d:4,desc:'Essential for vision, immunity, and cell growth. Deficiency affects about 190 million children worldwide, mostly in developing countries. Animal-source vitamin A (retinol) absorbs well, while plant-source conversion from beta-carotene varies greatly between individuals. Never exceed 3,000 mcg per day. High doses cause liver damage and birth defects.',dose:'700–900 mcg RAE/day from food + supplementation; do NOT exceed 3,000 mcg RAE/day'},
{t:'t2',n:'Bromelain',iN:true,tag:'Inflammation · Sinusitis · Recovery',e:3,s:4,r:3,o:3,c:3,d:4,desc:'A natural enzyme from pineapple stems that helps reduce swelling and pain. A 2024 review of 8 trials found it significantly reduces post-surgical swelling and recovery time. Approved in Germany as a treatment for sinus inflammation. Take between meals for anti-inflammatory effects or with meals to help digest protein. Generally well tolerated.',dose:'500–1,000 mg/day (2,400–2,800 GDU/g) between meals for inflammation; with food for digestion'},
{t:'t2',n:'D-Mannose',iN:true,tag:'UTI prevention · Bladder health',e:3,s:5,r:3,o:4,c:3,d:5,desc:'Helps prevent recurring urinary tract infections naturally. A 2024 Cochrane update of 7 trials found D-mannose significantly reduces recurring UTIs in women, working as well as low-dose antibiotics. It works by preventing bacteria from sticking to the bladder wall. Very safe with no significant side effects. Can be used alongside cranberry extract.',dose:'2 g/day for prevention; 2 g × 3 daily for 3 days at symptom onset'},
{t:'t2',n:'Astragalus (Astragalus membranaceus)',iN:true,tag:'Immunity · Adaptogen · Anti-aging',e:3,s:4,r:4,o:2,c:3,d:4,desc:'A traditional Chinese herb with modern evidence for boosting immune function. A 2024 review found it significantly improved immune cell counts when used alongside conventional treatment for respiratory infections and cancer. Has been used safely in traditional medicine for centuries. Avoid if you take immunosuppressant medications.',dose:'500–1,000 mg/day standardised extract (0.4–0.5% astragaloside IV)'},
{t:'t2',n:'Phosphatidylcholine',iN:true,tag:'Liver · Cell membrane · Cognition',e:3,s:5,r:3,o:2,c:2,d:4,desc:'A key building block of every cell membrane in your body. A 2024 review of 9 trials found it significantly improves liver function in people with fatty liver disease. Also supports brain signaling by providing choline, which most people don\'t get enough of. The sunflower-derived form is preferred for people with soy allergies. Very safe at standard doses.',dose:'900–1,800 mg/day with meals; sunflower-derived form preferred for soy-allergic individuals'},
{t:'t2',n:'Vitamin E (mixed tocopherols)',iN:true,tag:'Antioxidant · Skin · NAFLD',e:3,s:3,r:3,o:2,c:2,d:4,desc:'The PIVENS trial found 800 IU per day significantly improved liver inflammation in fatty liver disease. Mixed tocopherol forms are preferred over alpha-tocopherol alone for general use. Cochrane warns doses above 400 IU per day may increase death risk, so high-dose use should only be under medical supervision for specific liver conditions.',dose:'200–400 IU/day mixed tocopherols; 800 IU/day only for NASH under medical supervision'},
{t:'t2',n:'Potassium citrate',iN:true,tag:'Blood pressure · Muscle · Electrolyte',e:4,s:4,r:3,o:3,c:3,d:4,desc:'Helps lower blood pressure and supports proper muscle and nerve function. WHO confirms increased potassium significantly reduces blood pressure. A striking 97% of Americans don\'t get the recommended amount from their diet. Most effective when you also reduce sodium intake. Get potassium from foods like bananas and potatoes when possible.',dose:'500–1,000 mg/day supplemental potassium citrate; dietary sources (banana, potato) preferred'},
{t:'t2',n:'Lactoferrin',iN:true,tag:'Iron absorption · Immunity · Gut',e:3,s:5,r:3,o:3,c:3,d:4,desc:'A gentle way to improve iron levels without the stomach side effects of standard iron pills. A 2024 review of 14 trials found lactoferrin significantly improves iron levels in pregnancy and anemia. Also boosts immunity by supporting your body\'s natural defenses. Can be combined with iron supplements for even better absorption. Very well tolerated.',dose:'100–250 mg/day bovine lactoferrin; can be combined with iron for enhanced absorption'},
{t:'t3',n:'Chlorella',iN:true,tag:'Detox · Immunity · Cholesterol',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A nutrient-dense freshwater algae. A 2025 review of 11 trials found modest reductions in cholesterol and blood sugar. Claims about removing heavy metals from the body are not well supported in human studies. Rich in chlorophyll, protein, and B vitamins. The broken-cell-wall form absorbs better. Generally safe when sourced from reputable suppliers.',dose:'3–6 g/day broken-cell-wall chlorella powder or tablets'},
{t:'t3',n:'Moringa (Moringa oleifera)',iN:true,tag:'Antioxidant · Glucose · Inflammation',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A nutrient-dense plant with modest evidence for blood sugar reduction. A 2024 review of 8 trials found a small but significant blood sugar reduction in type 2 diabetes. Rich in antioxidants, vitamins, and minerals. NCCIH warns of limited safety data and possible interactions with thyroid and diabetes medications. Avoid seed and root extracts.',dose:'1–2 g/day moringa leaf powder; avoid seed or root extracts (safety concerns)'},
{t:'t3',n:'Elderflower extract',iN:true,tag:'Upper respiratory · Antiviral · Sinus',e:2,s:4,r:2,o:3,c:3,d:4,desc:'Related to but different from elderberry, and with much weaker evidence. Traditionally used for sinus and upper respiratory inflammation in European herbal medicine. Very limited trial data exists, as most evidence comes from lab studies only. Generally considered safe for short-term use. If you want elderberry benefits, choose elderberry itself instead.',dose:'500–1,000 mg/day standardised extract; evidence insufficient for strong recommendation'},
{t:'t3',n:'Bee propolis',iN:true,tag:'Immunity · Wound healing · Oral health',e:2,s:3,r:2,o:2,c:3,d:4,desc:'A resinous substance bees make to protect their hives. A 2024 review of 15 trials found significant improvements in mouth sore healing and wound recovery. Has confirmed antimicrobial and anti-inflammatory properties in both lab and human studies. Avoid entirely if allergic to bee products or pollen, as serious allergic reactions can occur.',dose:'300–500 mg/day standardised extract; contraindicated in bee/pollen allergy'},
{t:'t3',n:'Pine bark extract (Pycnogenol)',iN:true,tag:'Circulation · Skin · Antioxidant',e:2,s:4,r:2,o:2,c:2,d:4,desc:'A potent antioxidant extract from French maritime pine bark. Multiple small trials show improvements in poor leg circulation, skin elasticity, and blood vessel function. Contains similar active compounds to grape seed extract. Generally well tolerated with a good safety record. Most evidence comes from small, manufacturer-funded studies.',dose:'100–200 mg/day standardised extract (65–75% procyanidins)'},
{t:'t3',n:'DIM (Diindolylmethane)',iN:true,tag:'Estrogen metabolism · Hormonal balance',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A compound naturally found in cruciferous vegetables like broccoli and cauliflower. Small trials suggest it helps shift estrogen metabolism in a favorable direction. NCCIH says evidence is insufficient for cancer prevention claims. May alter hormone levels, so consult an endocrinologist if you are on hormone replacement therapy before using this.',dose:'100–200 mg/day; may alter estrogen metabolism — consult endocrinologist if on HRT'},
{t:'t3',n:'Methyl B12 + Methylfolate combo',iN:true,tag:'MTHFR · Methylation · Energy',e:2,s:4,r:2,o:3,c:3,d:4,desc:'Marketed to people with the MTHFR gene variant, which about 40% of the population carries. NIH notes most carriers have perfectly normal folate metabolism and do not need special supplements. Only clinically needed when blood tests actually show low folate, low B12, or elevated homocysteine levels. Safe but usually unnecessary for healthy people.',dose:'1,000 mcg methyl-B12 + 400 mcg 5-MTHF/day; test homocysteine and serum levels first'},
{t:'t3',n:'Mushroom complex (multi-species)',iN:true,tag:'Immunity · Adaptogen · Cognition',e:2,s:4,r:2,o:2,c:3,d:4,desc:'Blends of reishi, chaga, cordyceps, turkey tail, and others. Each mushroom has varying levels of evidence individually, but combined blends lack standardized dosing. No trials have tested the specific combinations being sold commercially. You are better off choosing a single mushroom species with evidence for your specific health goal.',dose:'1–3 g/day mushroom blend; species-specific extracts with standardised beta-glucans preferred'},
{t:'t3',n:'Inulin / FOS (prebiotic fibre)',iN:true,tag:'Gut microbiome · Calcium absorption',e:2,s:4,r:2,o:3,c:4,d:5,desc:'Feeds the beneficial bacteria in your gut, helping them thrive. A 2024 review of 18 trials found it significantly increases beneficial gut bacteria and improves calcium absorption. Bloating and gas are common side effects above 10 g per day. Start with a low dose and increase gradually over 1 to 2 weeks to minimize digestive discomfort.',dose:'5–10 g/day; start at 2–3 g/day and titrate up to minimise bloating'},
{t:'t3',n:'Tongkat ali (Eurycoma longifolia)',iN:true,tag:'Testosterone · Male health',e:2,s:2,r:2,o:2,c:2,d:2,desc:'A 2022 review of 5 trials found significant testosterone improvement in men with low testosterone. However, a 2024 trial in healthy trained adults showed no benefit, suggesting it only helps those who are already deficient. European authorities flagged potential DNA damage concerns in animal studies. Limit use to 6 months maximum.',dose:'200–400 mg/day standardised extract — only if confirmed hypogonadal; max 6 months'},
{t:'t2',n:'Copper (as glycinate)',iN:true,tag:'Iron metabolism · Collagen · Immunity',e:3,s:3,r:3,o:3,c:3,d:4,desc:'Essential for iron metabolism, collagen formation, and antioxidant defense in the body. If you take zinc supplements above 25 mg per day long-term, you likely need copper too because zinc depletes copper over time. Most people get enough copper from food, but zinc supplementation can create an imbalance. Safe at recommended doses of 1 to 2 mg per day.',dose:'1–2 mg/day copper glycinate; required if supplementing zinc >25 mg/day long-term'},
{t:'t4',n:'Usnic acid (weight loss)',iN:true,tag:'Hepatotoxicity · Mitochondrial uncoupling',e:1,s:1,r:1,o:3,c:1,d:1,desc:'A lichen-derived compound marketed for fat loss, but extremely dangerous. Multiple reports of acute liver failure have been documented, including cases requiring liver transplant and at least one death. FDA issued warnings back in 2001. There is no trial evidence that it even works for weight loss. No safe dose has been established.',dose:'AVOID — no safe dose established; severe hepatotoxicity risk'},
{t:'t1',n:'Calcium',iN:true,tag:'Bone · Muscle · Nerve',e:4,s:4,r:4,o:3,c:5,d:4,desc:'Essential for strong bones, muscle function, and nerve signaling. Postmenopausal women benefit most from supplementation to prevent bone density loss. Don\'t take more than 500 mg at a time for best absorption. Pair with Vitamin D3 and K2 for optimal bone health. The citrate form absorbs better than carbonate, especially if you have low stomach acid.',dose:'500–1,000 mg/day in divided doses (citrate form preferred); pair with Vitamin D3 and K2'},
{t:'t1',n:'Electrolyte complex (Na/K/Mg)',iN:true,tag:'Hydration · Performance · Recovery',e:4,s:5,r:4,o:5,c:5,d:5,desc:'Replaces the key minerals you lose through sweat during exercise. Sports nutrition experts confirm that replacing sodium, potassium, and magnesium during exercise over 60 minutes significantly improves endurance, prevents cramping, and maintains hydration. Especially important in hot weather or for heavy sweaters. Very safe at recommended doses.',dose:'300–600 mg sodium + 75–150 mg potassium + 50–100 mg magnesium per hour of intense exercise'},
{t:'t2',n:'Andrographis paniculata',iN:true,tag:'Immunity · Cold/Flu · Inflammation',e:3,s:4,r:2,o:3,c:3,d:4,desc:'Can shorten colds and reduce severity when taken early. A 2024 Cochrane review of 7 trials found it significantly shortens colds and reduces severity when started within 36 hours of first symptoms. Well-tolerated for short-term use during acute illness. Most effective with extracts standardized to at least 30% andrographolides. Not for daily prevention.',dose:'400 mg standardised extract (≥30% andrographolides) × 3 daily for 5 days at symptom onset'},
{t:'t2',n:'Gamma-linolenic acid (GLA)',iN:true,tag:'Inflammation · Eczema · PMS',e:3,s:4,r:2,o:2,c:3,d:4,desc:'Helps relieve eczema symptoms and PMS-related breast pain. A 2024 review of 11 trials found evening primrose oil, which contains the active omega-6 fatty acid GLA, significantly improves both conditions. The anti-inflammatory effects typically take 8 to 12 weeks to become noticeable. Generally well tolerated with mild digestive side effects.',dose:'1,000–2,000 mg/day evening primrose oil (~80–160 mg GLA) or 500 mg borage oil (~100 mg GLA)'},
{t:'t2',n:'S-Adenosylmethionine (SAMe)',iN:true,tag:'Depression · Joint · Liver',e:3,s:4,r:3,o:3,c:3,d:3,desc:'A natural compound your body makes that supports mood, joint health, and liver function. Multiple reviews found SAMe significantly helps with depression, performing as well as older antidepressant medications, and also reduces arthritis pain. Supports production of glutathione, the body\'s master antioxidant. Must use enteric-coated form on an empty stomach.',dose:'800–1,600 mg/day in divided doses on empty stomach; enteric-coated form required'},
{t:'t2',n:'Nattokinase',iN:true,tag:'Cardiovascular · Fibrinolysis · Blood pressure',e:3,s:3,r:3,o:3,c:3,d:2,desc:'A natural enzyme from fermented soybeans that may support cardiovascular health. A 2024 review of 15 trials found nattokinase significantly lowers blood pressure by about 4.5 mmHg and reduces blood-clotting protein levels. Do not take with blood thinners like warfarin or aspirin, as the combined effect could cause dangerous bleeding.',dose:'2,000–4,000 FU/day (100–200 mg); AVOID with warfarin, aspirin, or other blood thinners'},
{t:'t2',n:'Vitamin C (moderate dose)',iN:true,tag:'Immunity · Collagen · Antioxidant',e:3,s:5,r:3,o:3,c:5,d:5,desc:'Essential for collagen production, immunity, and iron absorption. Cochrane found regular supplementation shortens colds by 8% in adults and 14% in children. Your body can only absorb about 200 mg at a time, so higher doses are mostly wasted. Pair with iron supplements to boost iron absorption. Very safe at moderate doses with no serious side effects.',dose:'200–500 mg/day; higher doses are excreted. Pair with iron supplements to enhance absorption'},
{t:'t2',n:'Cranberry extract',iN:true,tag:'UTI prevention · Bladder health',e:3,s:5,r:4,o:3,c:3,d:4,desc:'Helps prevent urinary tract infections, especially in women who get them frequently. A 2024 Cochrane update of 50 trials (8,857 people) found cranberry reduces recurring UTI risk by 27%. Works by preventing bacteria from sticking to the bladder wall. Very safe with no serious side effects. Choose concentrated extract over juice to avoid excess sugar.',dose:'500 mg concentrated extract/day (≥36 mg PACs/day); or 240 mL unsweetened juice'},
{t:'t3',n:'PQQ (Pyrroloquinoline quinone)',iN:true,tag:'Mitochondria · Cognition · Energy',e:2,s:4,r:2,o:2,c:2,d:4,desc:'Stimulates your cells to produce new energy-generating mitochondria, which may help combat age-related energy decline. Small trials show improved sleep quality and reduced fatigue. A 2024 trial found improved mental flexibility in older adults. Often combined with CoQ10 for synergistic effects. Generally safe, though long-term data is still limited.',dose:'10–20 mg/day with food; often combined with CoQ10'},
{t:'t3',n:'Apigenin',iN:true,tag:'Sleep · Anxiety · Neuroprotection',e:2,s:4,r:2,o:4,c:3,d:5,desc:'A compound found in chamomile that gently activates the brain\'s calming receptors. Provides mild anxiety relief without drowsiness or dependency. Also helps preserve NAD+, a molecule linked to aging. Human trial data is still limited, but the safety profile is excellent. Chamomile extract standardized for apigenin is the preferred form.',dose:'50–100 mg/day; chamomile extract standardised to apigenin preferred'},
{t:'t2',n:'Theacrine (TeaCrine)',iN:true,tag:'Energy · Focus · Tolerance-free',e:3,s:4,r:2,o:4,c:3,d:5,desc:'Provides clean energy similar to caffeine but without the tolerance buildup. 2024 trials found comparable energy and focus benefits with no tolerance even after 8 weeks of daily use. Unlike caffeine, it doesn\'t raise heart rate or blood pressure. Can be combined with caffeine for a stronger effect without jitters. Well tolerated in studies.',dose:'100–200 mg/day; can combine with caffeine for synergistic effect without jitters'},
{t:'t2',n:'Sunfiber (partially hydrolysed guar gum)',iN:true,tag:'Gut · IBS · Prebiotic',e:3,s:5,r:2,o:3,c:3,d:5,desc:'A gentle prebiotic fiber that helps with both constipation and diarrhea. A 2024 review of 12 trials found it significantly improves IBS symptoms of both types, increases beneficial gut bacteria, and normalizes stool form. Unlike many fibers, it is safe for low-FODMAP diets and dissolves completely in water without altering taste or texture.',dose:'5–7 g/day dissolved in water or food; well-tolerated even in FODMAP-sensitive patients'},
{t:'t2',n:'Stinging nettle root (Urtica dioica)',iN:true,tag:'Prostate · Allergies · Inflammation',e:3,s:4,r:3,o:2,c:3,d:4,desc:'Two different parts of the plant serve two different purposes. A 2024 review of 6 trials found nettle root significantly improves urinary symptoms in men with enlarged prostate. The leaf form has separate evidence for seasonal allergies, where it may help reduce sneezing and itching. Generally well tolerated with a good safety profile.',dose:'Root: 300–600 mg/day for BPH. Leaf: 300 mg freeze-dried × 3 daily for allergies'},
{t:'t2',n:'Tributyrin / Butyrate',iN:true,tag:'Gut barrier · Microbiome · Inflammation',e:3,s:4,r:2,o:3,c:3,d:5,desc:'Butyrate is the main fuel source for the cells lining your colon and is critical for maintaining gut barrier health. The tributyrin form survives stomach acid better than sodium butyrate and releases butyrate directly in the colon. 2024 trials show improved gut lining integrity. Generally safe but can cause mild digestive changes initially.',dose:'300–600 mg/day tributyrin; or 2–4 g/day sodium butyrate'},
{t:'t3',n:'Maca (Lepidium meyenii)',iN:true,tag:'Libido · Energy · Fertility',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A Peruvian root vegetable traditionally used for energy and libido. A 2024 review of 9 trials found modest improvements in libido and perceived energy, but no significant effect on testosterone levels. NCCIH considers it generally safe for short-term use. The gelatinized form is easier on the stomach. Allow 6 to 8 weeks to assess benefits.',dose:'1,500–3,000 mg/day gelatinised maca powder; allow 6–8 weeks for assessment'},
{t:'t4',n:'Colloidal silver',iN:true,tag:'Antimicrobial claims · Toxicity',e:1,s:1,r:1,o:3,c:1,d:3,desc:'FDA says there is no legitimate medical use as a supplement and has taken action against companies making false health claims. Causes irreversible permanent blue-grey skin discoloration called argyria. No trial evidence supports any health benefit. Despite marketing claims, it has no proven antimicrobial benefit when taken orally as a supplement.',dose:'AVOID — no safe or effective dose; causes permanent skin discolouration'},
{t:'t3',n:'Activated charcoal (oral)',iN:true,tag:'Detox claims · Gas',e:1,s:3,r:1,o:4,c:3,d:3,desc:'Only has evidence for emergency poisoning treatment in hospitals (within 1 hour of ingestion). No evidence supports "detox" benefits or daily wellness use. It binds medications and nutrients indiscriminately, reducing their effectiveness. Taking it regularly can actually prevent your body from absorbing important vitamins and medications you need.',dose:'Not recommended as a supplement; medical use only for acute poisoning'},
{t:'t3',n:'Biotin (high-dose)',iN:true,tag:'Hair · Nails · Skin',e:2,s:3,r:2,o:3,c:3,d:4,desc:'Biotin deficiency is rare in people who eat a normal diet. No trial evidence that supplements improve hair or nails in people who aren\'t deficient. Warning: doses above 5,000 mcg per day cause false results on heart and thyroid blood tests, which can lead to misdiagnosis. Stop high-dose biotin at least 48 hours before any lab work.',dose:'30–100 mcg/day adequate; high-dose supplements (5,000–10,000 mcg) lack evidence and interfere with lab tests'},
{t:'t3',n:'Apple cider vinegar (supplement)',iN:true,tag:'Glucose · Weight · Digestion',e:2,s:3,r:2,o:3,c:3,d:4,desc:'A 2024 review of 9 trials found modest reductions in blood sugar and body weight (about 1.2 kg over 12 weeks), but the effects are small. Liquid vinegar can erode tooth enamel and irritate the throat, so capsules are a safer option. Take with meals to reduce stomach irritation. Not a replacement for proper diet and exercise.',dose:'750–1,500 mg/day capsule form; take with meals to reduce GI irritation'},
{t:'t3',n:'Carnosine (L-carnosine)',iN:true,tag:'Anti-glycation · Aging · Athletic',e:2,s:4,r:2,o:2,c:3,d:4,desc:'An antioxidant concentrated in muscle and brain tissue that helps prevent sugar-related protein damage, a process linked to aging. Small trials show modest benefits for slowing age-related decline, but the body breaks it down quickly in the bloodstream. Beta-alanine may be a more effective way to raise carnosine levels in muscles.',dose:'500–1,000 mg/day in divided doses; beta-alanine may be more effective for raising muscle carnosine'},
{t:'t3',n:'Sea moss (Irish moss)',iN:true,tag:'Thyroid · Minerals · Gut',e:1,s:3,r:1,o:3,c:1,d:3,desc:'Rich in iodine and trace minerals, but no human trial evidence supports any health claim. Popular on social media but completely lacking in clinical research. Iodine content varies wildly between batches, creating a real risk of thyroid problems from excessive or inconsistent intake. Test your thyroid function before use. Not recommended.',dose:'No evidence-based dose; iodine content unpredictable — test thyroid function before use'},
{t:'t3',n:'Fulvic acid',iN:true,tag:'Mineral absorption · Antioxidant · Gut',e:1,s:3,r:1,o:3,c:1,d:4,desc:'A soil-derived substance marketed for improved mineral absorption and "detox." No human trial evidence supports any health benefit whatsoever. Comes with a documented risk of heavy metal contamination including lead, arsenic, and mercury. Product quality and purity vary enormously between brands. Save your money for supplements with actual evidence.',dose:'No evidence-based dose; quality and purity vary widely; contamination risk'},
{t:'t3',n:'Diatomaceous earth (food grade)',iN:true,tag:'Detox claims · Silica',e:1,s:3,r:1,o:3,c:1,d:5,desc:'Marketed for "detox" and silica content, but no trial evidence supports any health benefit. Made from fossilized algae and used mainly as a pest control product. The food-grade form is generally considered safe to consume, but no therapeutic claims are supported by science. Your money is better spent on supplements with actual clinical evidence.',dose:'No evidence-based dose; no clinical benefit demonstrated'},
{t:'t3',n:'Enzyme CoQ10 + PQQ stack',iN:true,tag:'Mitochondria · Energy · Aging',e:2,s:4,r:2,o:3,c:2,d:4,desc:'A popular anti-aging combination of CoQ10 with PQQ, designed to support cellular energy production and mitochondrial health. The theory behind combining them makes scientific sense, but no trials have tested whether the combination actually works better than taking either one alone. Both individual ingredients have decent safety profiles.',dose:'200 mg ubiquinol + 20 mg PQQ/day; combination lacks direct RCT evidence'},
{t:'t2',n:'Lactobacillus rhamnosus GG',iN:true,tag:'Gut · IBS · Pediatric diarrhoea',e:4,s:5,r:4,o:3,c:3,d:4,desc:'The most studied probiotic strain in the world, with decades of clinical research behind it. Cochrane confirms it significantly shortens diarrhea in children by about 1 day. A 2024 review also found it effective for IBS-related and antibiotic-caused diarrhea. Very safe even for infants. Refrigerated strains maintain better viability.',dose:'10–20 billion CFU/day; refrigerated strains preferred for viability'},
{t:'t2',n:'Saccharomyces boulardii',iN:true,tag:'Gut · C. diff · Traveller diarrhoea',e:4,s:5,r:4,o:3,c:3,d:4,desc:'A unique probiotic yeast that antibiotics cannot kill, making it the only probiotic you can take during an antibiotic course without it being destroyed. Cochrane confirms it significantly reduces C. difficile recurrence and traveler\'s diarrhea. Very safe with an excellent track record. An essential travel companion for high-risk destinations.',dose:'250–500 mg (5–10 billion CFU) × 2 daily; safe during antibiotic courses'},
{t:'t2',n:'Bifidobacterium longum',iN:true,tag:'Gut · Immunity · Mood-gut axis',e:3,s:5,r:3,o:3,c:3,d:4,desc:'Helps reduce stress through the gut-brain connection. A 2024 review of 16 trials found the 1714 strain significantly reduces perceived stress and the morning cortisol spike. Also improves gut barrier health. A great example of how gut bacteria influence your brain and mood. Very safe with no serious side effects. Strain-specific evidence is strongest.',dose:'1–10 billion CFU/day; strain-specific evidence (1714 for stress, BB536 for immunity)'},
{t:'t2',n:'Conjugated linoleic acid (CLA)',iN:true,tag:'Body composition · Fat loss',e:2,s:3,r:3,o:2,c:3,d:3,desc:'May help reduce body fat slightly, but the effect is small. A 2024 review of 18 trials found CLA significantly reduces body fat, but only by about 0.7 kg on average. May worsen insulin resistance and increase liver fat in some people, which limits its usefulness. Monitor your metabolic markers if you decide to try it. Not a weight loss solution.',dose:'3.2–6.4 g/day mixed isomers (c9,t11 + t10,c12); monitor metabolic markers'},
{t:'t2',n:'Tyrosine (L-tyrosine)',iN:true,tag:'Focus · Stress resilience · Cognition',e:3,s:5,r:3,o:4,c:4,d:5,desc:'A building block for the brain chemicals dopamine and adrenaline. Military trials show it significantly preserves mental performance under acute stress, sleep deprivation, and cold exposure. Will not boost cognition under normal, rested conditions. Take 30 to 60 minutes before stressful situations. Very safe with no serious side effects.',dose:'500–2,000 mg 30–60 min before acute stress or demanding cognitive tasks'},
{t:'t3',n:'Omega-7 (Palmitoleic acid)',iN:true,tag:'Metabolic · Inflammation · Skin',e:2,s:4,r:2,o:2,c:2,d:4,desc:'A lesser-known fatty acid with emerging health benefits. A 2024 review of 6 trials found sea buckthorn-derived omega-7 significantly reduces inflammation and improves vaginal dryness in postmenopausal women. Early research also suggests metabolic benefits for blood sugar and cholesterol. Generally well tolerated. Research is still in early stages.',dose:'200–400 mg/day purified palmitoleic acid from sea buckthorn'},
{t:'t2',n:'Methylsulfonylmethane (MSM)',iN:true,tag:'Joint · Inflammation · Recovery',e:3,s:5,r:3,o:3,c:3,d:4,desc:'Helps reduce joint pain and improve physical function in people with knee arthritis. A 2024 review of 12 trials confirmed these benefits. Also reduces markers of exercise-induced muscle damage, making it useful for athletes. Allow 8 to 12 weeks for full joint benefits. Very safe with an excellent tolerance profile and no serious side effects.',dose:'1,500–3,000 mg/day in divided doses; allow 8–12 weeks for joint benefits'},
{t:'t3',n:'Cistanche deserticola',iN:true,tag:'Cognition · Testosterone · Anti-aging',e:2,s:4,r:2,o:2,c:2,d:4,desc:'A traditional Chinese herb showing early promise for brain health. A 2024 trial found 450 mg per day improved cognitive test scores in elderly adults over 12 weeks. Animal studies also support testosterone and cellular energy benefits, but human evidence is still limited. Generally well tolerated in the studies conducted so far. More research is needed.',dose:'450–1,000 mg/day standardised extract; human evidence still limited'},
{t:'t2',n:'Black cohosh (Cimicifuga racemosa)',iN:true,tag:'Menopause · Hot flashes · Mood',e:3,s:3,r:4,o:2,c:3,d:2,desc:'One of the better-studied natural options for menopause relief. A 2024 Cochrane update of 16 trials found it significantly reduces hot flash frequency and severity during menopause. Rare cases of liver damage have been reported, so liver function monitoring is recommended during use. Limit use to 6 months at a time at standard doses.',dose:'20–40 mg/day standardised extract (1 mg triterpene glycosides); max 6 months'},
{t:'t2',n:'Glycerophosphocholine (GPC)',iN:true,tag:'Cognition · Stroke recovery · Growth hormone',e:3,s:4,r:2,o:2,c:2,d:3,desc:'A highly absorbable choline source that readily crosses the blood-brain barrier. A 2024 review found it improves cognitive function in dementia and aids stroke recovery. One trial also showed 600 mg acutely boosted growth hormone release. Generally well tolerated with few side effects. Provides the choline most people lack in their diet.',dose:'300–600 mg/day for cognition; 600 mg pre-exercise for GH (single study)'},
{t:'t3',n:'Resolvins / SPMs (Specialised Pro-resolving Mediators)',iN:true,tag:'Inflammation resolution · Recovery',e:2,s:4,r:2,o:2,c:2,d:4,desc:'Derived from omega-3 fatty acids, these molecules actively resolve inflammation rather than just suppressing it, representing a newer approach to managing inflammation. 2024 trials found SPM supplements significantly reduce post-exercise inflammation. Still an emerging area of research with no established standard dosing. Generally well tolerated.',dose:'500–1,000 mg/day SPM-enriched fish oil; emerging evidence — standard dosing not established'},
{t:'t3',n:'Urolithin A',iN:true,tag:'Mitophagy · Muscle · Aging',e:2,s:4,r:2,o:2,c:2,d:4,desc:'A compound your gut bacteria produce from pomegranate and certain berries that supports cellular energy and muscle health. A 2024 trial found 1,000 mg per day for 4 months improved muscle endurance and cellular energy markers in older adults. Not everyone produces it naturally from food, making supplementation potentially useful for some people.',dose:'500–1,000 mg/day (Mitopure form studied); not everyone produces urolithin A endogenously'},
{t:'t3',n:'Cordyceps militaris',iN:true,tag:'Endurance · Energy · Oxygen utilisation',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A medicinal mushroom traditionally used for energy and stamina. A 2024 review of 7 trials found modest improvements in aerobic capacity and exercise endurance. Most positive trials used the cultivated form (C. militaris), not wild cordyceps. Evidence is still inconsistent across studies. Generally safe, but quality varies widely between products.',dose:'1,000–3,000 mg/day C. militaris extract; CS-4 strain for standardisation'},
{t:'t3',n:'Reishi (Ganoderma lucidum)',iN:true,tag:'Immunity · Sleep · Adaptogen',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A traditional medicinal mushroom with confirmed immune-modulating effects in lab studies. In humans, evidence is limited to improved quality of life alongside cancer treatment. Sleep and stress-relief claims lack rigorous trial support. Requires dual extraction (hot water plus alcohol) to release active compounds. Generally safe for most people.',dose:'1,000–3,000 mg/day dual-extracted (hot water + alcohol) fruiting body'},
{t:'t3',n:'Turkey tail (Trametes versicolor)',iN:true,tag:'Immunity · Cancer adjunct · Gut',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A medicinal mushroom whose active compounds are approved as cancer treatment support in Japan. Western clinical trials are limited but growing. A 2024 pilot study showed improved gut bacteria diversity in breast cancer survivors after chemotherapy. Generally well tolerated. Choose extracts standardized for the active compounds PSK and PSP.',dose:'1,000–3,000 mg/day standardised PSK/PSP extract'},
{t:'t3',n:'Rhodiola crenulata',iN:true,tag:'Altitude · Endurance · Distinct species',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A different species from the more common Rhodiola rosea, traditionally used in Tibetan medicine for altitude sickness. A 2024 trial found 800 mg per day significantly reduced altitude sickness symptoms. Watch out when purchasing because products often mix up the two species. Verify the label says crenulata, not rosea. Limited safety data.',dose:'400–800 mg/day standardised extract; verify species (crenulata, not rosea)'},
{t:'t3',n:'Grape seed extract (OPC)',iN:true,tag:'Antioxidant · Circulation · Blood pressure',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A plant antioxidant that may modestly lower blood pressure. A 2024 review of 15 trials found a small but significant blood pressure reduction of about 3.2 mmHg. Its antioxidants improve blood vessel function, but overall heart health evidence is weaker than expected given the strong lab data. Generally well tolerated with no major side effects.',dose:'150–300 mg/day standardised extract (≥95% OPCs)'},
{t:'t3',n:'Horny goat weed (Epimedium)',iN:true,tag:'Libido · Erectile function · Bone',e:2,s:3,r:2,o:2,c:2,d:3,desc:'Contains icariin, a compound that works on similar pathways to Viagra in lab studies. Only small human trials exist, and most evidence comes from animal and lab studies rather than real-world clinical research. Product quality and potency vary widely between brands. Not recommended as a first-line option. Consult your doctor for sexual health concerns.',dose:'250–1,000 mg/day standardised extract (10–20% icariin); evidence insufficient for recommendation'},
{t:'t3',n:'Mucuna pruriens',iN:true,tag:'Dopamine · Testosterone · Mood',e:2,s:3,r:2,o:2,c:2,d:2,desc:'Naturally contains L-DOPA (3 to 6%), which is a direct precursor to the brain chemical dopamine. A 2024 trial showed improved sperm quality and testosterone in infertile men. Warning: interacts dangerously with Parkinson\'s medications and certain antidepressants. Should only be used under medical supervision due to its potent dopamine effects.',dose:'300–600 mg/day standardised extract (15–20% L-DOPA); AVOID with levodopa or MAOIs'},
{t:'t3',n:'Slippery elm (Ulmus rubra)',iN:true,tag:'Gut · GERD · Sore throat',e:2,s:4,r:2,o:3,c:3,d:4,desc:'A soothing bark that coats and protects irritated digestive and throat surfaces. Traditional use for acid reflux, IBS, and sore throat spans centuries. No human trials exist, and all evidence is based on historical use and theoretical support. Generally well tolerated. Take 2 hours away from medications because it may slow their absorption.',dose:'400–800 mg/day or 1–2 tbsp bark powder in water; take 2 hrs away from medications (may impair absorption)'},
{t:'t3',n:'Policosanol',iN:true,tag:'Cholesterol · Cardiovascular',e:2,s:4,r:2,o:2,c:3,d:4,desc:'Derived from sugar cane wax and marketed for cholesterol reduction. Cuban studies claimed dramatic cholesterol reductions, but every independent study conducted outside Cuba has consistently shown no significant effect. This is a notable example of research results that could not be replicated by other laboratories. Not recommended for cholesterol management.',dose:'10–20 mg/day; independent studies found no benefit — Cuban results not replicated'},
{t:'t3',n:'DHEA (Dehydroepiandrosterone)',iN:true,tag:'Hormonal · Aging · Adrenal',e:2,s:2,r:2,o:2,c:2,d:2,desc:'A precursor hormone your adrenal glands produce that declines with age. A 2024 review found modest bone density improvements in postmenopausal women. Banned in competitive sports by most organizations. Can raise both estrogen and testosterone levels, so it requires regular hormone monitoring by your doctor. Not recommended for healthy adults.',dose:'25–50 mg/day in adrenal insufficiency only; not recommended for healthy adults; banned in competitive sports'},
{t:'t3',n:'Manuka honey (medicinal grade)',iN:true,tag:'Wound healing · Antimicrobial · Gut',e:2,s:4,r:2,o:3,c:2,d:4,desc:'Has strong Cochrane-supported evidence for wound healing when applied topically as medical-grade honey. However, oral supplement claims for gut health and immunity are not supported by human trials. Quality varies widely based on MGO content (UMF 15+ is medical grade). The topical use is legitimate, but oral supplements are not well supported.',dose:'Topical: medical-grade (UMF 15+) for wounds. Oral supplement: no evidence-based dose for health claims'},
{t:'t3',n:'Zeolite (clinoptilolite)',iN:true,tag:'Detox claims · Heavy metals',e:1,s:3,r:1,o:3,c:1,d:3,desc:'A volcanic mineral marketed for "detoxification," but no human trial evidence supports the claim that it removes heavy metals or toxins from your body. May actually bind and deplete beneficial minerals you need. Product quality and contamination risk vary widely between brands. Not recommended as a supplement by any health authority.',dose:'No evidence-based dose; not recommended as a supplement'},
{t:'t3',n:'Dong quai (Angelica sinensis)',iN:true,tag:'Menstrual · Menopause · Blood',e:2,s:3,r:2,o:2,c:3,d:2,desc:'A traditional Chinese herb sometimes called "female ginseng." Despite centuries of traditional use, Cochrane found insufficient evidence that it helps with menopausal symptoms like hot flashes. Warning: interacts with blood thinners such as warfarin and may cause increased sun sensitivity. Not recommended based on current clinical evidence.',dose:'500–1,000 mg/day standardised extract; AVOID with anticoagulants'},
{t:'t3',n:'Berberine + Ceylon cinnamon combo',iN:true,tag:'Glucose · Metabolic · Insulin',e:2,s:3,r:2,o:2,c:2,d:3,desc:'A popular blood sugar support combination sold by many supplement brands. Berberine has strong evidence on its own and cinnamon has modest evidence on its own, but no trials have tested whether combining them actually adds any benefit over berberine by itself. You may be paying extra for an unproven combination. Try berberine alone first.',dose:'500 mg berberine + 1,000 mg Ceylon cinnamon × 2 daily; combination not specifically validated'},
{t:'t3',n:'Collagen + Vitamin C stack',iN:true,tag:'Tendon · Skin · Joint',e:2,s:5,r:2,o:3,c:3,d:5,desc:'Vitamin C is required for your body to properly use collagen, making this combination logical. A 2024 trial found 15 g collagen plus 50 mg vitamin C taken before exercise enhanced tendon collagen production. Popular for injury prevention among athletes and people recovering from tendon or ligament injuries. Very safe with no notable side effects.',dose:'15 g collagen peptides + 50 mg vitamin C 30–60 min before exercise'},
{t:'t2',n:'Glutathione (liposomal)',iN:true,tag:'Antioxidant · Detoxification · Immunity',e:3,s:4,r:3,o:3,c:2,d:4,desc:'Your body\'s master antioxidant, essential for detoxification and immune defense. A 2024 review of 8 trials found liposomal glutathione significantly increases blood levels compared to placebo. Standard oral forms are poorly absorbed and mostly destroyed in digestion. You must use liposomal or S-acetyl forms for meaningful absorption.',dose:'500–1,000 mg/day liposomal or S-acetyl-glutathione; standard reduced glutathione is poorly absorbed'},
{t:'t2',n:'Benfotiamine',iN:true,tag:'Neuropathy · AGEs · Glucose metabolism',e:3,s:5,r:3,o:3,c:3,d:5,desc:'A fat-soluble form of vitamin B1 that absorbs about 5 times better than regular thiamine. A 2024 review of 7 trials found it significantly reduces diabetic nerve pain and sugar-related protein damage that contributes to complications. Very safe at recommended doses with no serious side effects. Especially useful for people with diabetes or prediabetes.',dose:'300–600 mg/day in divided doses with meals'},
{t:'t2',n:'Cissus quadrangularis',iN:true,tag:'Bone healing · Joint · Weight',e:3,s:4,r:2,o:2,c:2,d:4,desc:'Helps speed up bone fracture healing and reduces arthritis joint pain. A 2024 review of 9 trials confirmed these benefits with clinical significance. A traditional Ayurvedic plant now backed by modern clinical evidence. The standardized extract form (3% ketosterones) has the most research. Generally well tolerated with a good safety profile.',dose:'500–1,000 mg/day standardised extract (3% ketosterones)'},
{t:'t2',n:'Wobenzym (systemic enzymes)',iN:true,tag:'Inflammation · Recovery · OA',e:3,s:4,r:3,o:3,c:3,d:4,desc:'A combination of digestive enzymes and plant compounds used widely in European sports medicine. A 2024 review of 11 trials found it works as well as ibuprofen-type painkillers for knee arthritis with significantly fewer stomach side effects. Take on an empty stomach 30 minutes before meals for anti-inflammatory effects. Well tolerated overall.',dose:'2–3 tablets × 3 daily on empty stomach (30 min before meals)'},
{t:'t2',n:'Sulforaphane (broccoli sprout extract)',iN:true,tag:'Detoxification · Cancer prevention · Autism',e:3,s:4,r:3,o:3,c:3,d:4,desc:'A powerful compound from broccoli sprouts that activates your body\'s natural detox and antioxidant pathways. 2024 trials found it significantly helps clear air pollution toxins from the body. A promising trial also showed improved social behavior in autism. Choose products with active myrosinase enzyme for best conversion. Generally safe.',dose:'30–60 mg sulforaphane/day (equivalent to ~100g broccoli sprouts); stabilised myrosinase-active forms preferred'},
{t:'t3',n:'Pyruvate (calcium pyruvate)',iN:true,tag:'Weight management · Endurance · Metabolism',e:2,s:4,r:2,o:3,c:2,d:4,desc:'May help with modest fat loss by boosting cellular fat burning. A 2024 review of 6 trials found calcium pyruvate produces about 0.6 kg of fat loss. The effect is small but consistent across studies. High doses above 5 g per day commonly cause stomach discomfort. Not a significant weight loss solution on its own. Generally safe at moderate doses.',dose:'6–10 g/day in divided doses; GI discomfort common above 5g'},
{t:'t3',n:'Chlorophyll / Chlorophyllin',iN:true,tag:'Detox · Body odor · Antioxidant',e:1,s:4,r:1,o:3,c:2,d:4,desc:'Marketed as an internal "deodorant" and detox aid, but evidence is extremely thin. One 1980s study showed reduced toxin markers, but no modern clinical trials support general health claims. The chlorophyllin form absorbs better than natural chlorophyll. Generally safe, but there is not enough evidence to recommend it for any specific condition.',dose:'100–300 mg/day chlorophyllin; evidence insufficient for health recommendations'},
{t:'t3',n:'Tribulus terrestris',iN:true,tag:'Testosterone · Libido · Athletic',e:2,s:3,r:2,o:2,c:2,d:3,desc:'Despite widespread marketing as a testosterone booster, the evidence does not support this claim. A 2024 review of 12 trials found no significant effect on testosterone in healthy men. Some people report improved libido subjectively, but this may be placebo. European food safety authorities rejected all testosterone-related health claims.',dose:'250–750 mg/day standardised extract (40–45% saponins); no testosterone effect demonstrated'},
{t:'t3',n:'Chaga (Inonotus obliquus)',iN:true,tag:'Antioxidant · Immunity · Anti-tumor',e:1,s:3,r:1,o:2,c:2,d:3,desc:'A birch tree fungus with extremely high antioxidant activity in lab tests, but no human trials support any health claim. All anticancer evidence is from cell and animal studies, not human research. High oxalate content may increase kidney stone risk, especially in people with chronic kidney disease. Hot water extraction is needed to release active compounds.',dose:'1–3 g/day hot water extract; kidney stone risk from oxalates — avoid with CKD'},
{t:'t3',n:'Agaricus blazei (Royal Sun mushroom)',iN:true,tag:'Immunity · Blood sugar · Cancer adjunct',e:2,s:3,r:2,o:2,c:2,d:4,desc:'A medicinal mushroom with modest immune-boosting effects. A 2024 review found it may enhance immune function when used alongside cancer treatment. Small trials also show reduced blood sugar in type 2 diabetes. Product quality and active ingredient content vary widely between brands. Evidence is insufficient for a strong recommendation at this time.',dose:'500–1,500 mg/day standardised extract; evidence insufficient for strong recommendation'},
{t:'t4',n:'Fo-Ti (Polygonum multiflorum / He Shou Wu)',iN:true,tag:'Anti-aging · Hair · Liver risk',e:1,s:1,r:1,o:2,c:1,d:2,desc:'A traditional Chinese longevity herb that carries serious safety risks. NCCIH reports multiple cases of serious liver damage including liver failure and death linked to this herb. Despite centuries of traditional use, no human trial evidence supports anti-aging or hair growth claims. The risk of liver damage far outweighs any potential benefits.',dose:'AVOID — hepatotoxicity risk; no evidence of benefit'},
{t:'t3',n:'Bentonite clay (oral)',iN:true,tag:'Detox claims · GI binder',e:1,s:3,r:1,o:3,c:1,d:3,desc:'Marketed for "detox" and gut health, but no human trial evidence supports any health benefits. May bind medications, nutrients, and essential minerals in your digestive tract, reducing their absorption. FDA has warned about lead contamination in some commercial products. Not recommended as a dietary supplement by any major health authority.',dose:'No evidence-based dose; may interfere with medication absorption; contamination risk'},
{t:'t4',n:'Essential oils (oral, general)',iN:true,tag:'Various claims · Safety concerns',e:1,s:2,r:1,o:4,c:1,d:2,desc:'Only enteric-coated peppermint oil has clinical evidence for a health benefit, specifically for IBS symptoms. All other oral essential oils lack trial evidence and carry real risks of stomach irritation, liver damage, and drug interactions. Taking undiluted essential oils by mouth can burn your esophagus and stomach lining. Avoid oral ingestion.',dose:'Only enteric-coated peppermint oil has evidence; avoid oral ingestion of other essential oils'},
{t:'t3',n:'Omega-3-6-9 blends',iN:true,tag:'Cardiovascular · General wellness',e:2,s:4,r:2,o:3,c:2,d:4,desc:'These blends are a marketing strategy rather than a science-based product. Omega-9 is non-essential because your body makes it and food provides plenty. Western diets already have too much omega-6. Adding 6 and 9 to omega-3 products just dilutes the beneficial EPA and DHA you actually need. Buy pure omega-3 fish oil instead for better value.',dose:'Pure omega-3 (EPA/DHA) is superior; combination products dilute the active ingredients'},
{t:'t3',n:'Sambucol (elderberry extract, maintenance)',iN:true,tag:'Immunity · Prevention · Daily use',e:2,s:4,r:2,o:3,c:3,d:4,desc:'Evidence supports elderberry for treating active colds and flu when started within 48 hours of symptoms. However, no trial evidence supports daily maintenance use for immune "boosting" in healthy adults. Save it for when you actually get sick rather than taking it every day. Using it preventively is an unnecessary expense with no proven benefit.',dose:'Acute use only (15 mL × 4 daily for 3–5 days at symptom onset); daily maintenance use unsupported'},
{t:'t3',n:'Melatonin (high-dose, nightly)',iN:true,tag:'Sleep dependency · Hormone disruption',e:2,s:3,r:2,o:5,c:3,d:4,desc:'Different from the low-dose situational use recommended in Tier 1. Taking doses above 1 mg nightly can suppress your body\'s own melatonin production and disrupt your natural sleep-wake cycle. Long-term nightly use hasn\'t been well studied. Use the lowest effective dose (0.3 to 1 mg) only when needed for jet lag or shift work.',dose:'AVOID >1 mg nightly long-term; use 0.3–1 mg situationally only (jet lag, shift work)'},
{t:'t2',n:'Lactobacillus plantarum',iN:true,tag:'Gut health · Immunity · IBS',e:3,s:5,r:3,o:3,c:3,d:5,desc:'One of the most well-studied probiotic strains available today. A 2024 review found it significantly reduces IBS symptoms including bloating, gas, and abdominal pain. Also supports immune function by strengthening the gut barrier. The 299v and LP01 strains have the strongest clinical evidence. Very safe with no serious side effects reported.',dose:'10–20 billion CFU/day; strain-specific evidence strongest for 299v and LP01'},
{t:'t2',n:'Bifidobacterium breve',iN:true,tag:'Gut health · Infant health · Eczema',e:3,s:5,r:2,o:3,c:3,d:5,desc:'A probiotic strain naturally abundant in breastfed infants, playing a key role in early immune development. Trials show it reduces eczema severity in children and improves gut health in adults. Generally very well tolerated with no significant side effects reported. Evidence is strongest in pediatric populations for eczema prevention.',dose:'5–10 billion CFU/day; evidence strongest in paediatric populations for eczema prevention'},
{t:'t2',n:'Ox bile (bovine bile salts)',iN:true,tag:'Fat digestion · Gallbladder removal · Bile insufficiency',e:3,s:4,r:2,o:4,c:3,d:4,desc:'Supplemental bile acids help digest dietary fats when your own bile production is low. Most commonly needed after gallbladder removal. Reduces bloating, diarrhea, and fatty stool that many people experience after surgery. Start with a low dose and increase based on how well you tolerate it. Only needed with fat-containing meals.',dose:'100–500 mg with fat-containing meals; start low and increase based on tolerance'},
{t:'t2',n:'Betaine HCl',iN:true,tag:'Low stomach acid · Digestion · Protein absorption',e:3,s:3,r:2,o:4,c:4,d:4,desc:'Temporarily increases stomach acid to help your body digest protein more effectively. Useful for people with confirmed low stomach acid, which is common in older adults and those on long-term acid-blocking drugs. Do not use with anti-inflammatory painkillers or if you have stomach ulcers. Start with a low dose to test your tolerance.',dose:'650–2,000 mg with protein-containing meals; do not use with NSAIDs or if you have ulcers'},
{t:'t2',n:'R-Alpha lipoic acid',iN:true,tag:'Neuropathy · Blood sugar · Antioxidant',e:3,s:3,r:3,o:2,c:2,d:3,desc:'The natural R-form of alpha lipoic acid, which is more bioavailable than the synthetic racemic mix commonly sold. Multiple trials show it reduces diabetic neuropathy symptoms like numbness, tingling, and burning pain. Also supports healthy blood sugar levels. Take on an empty stomach for better absorption. May lower thyroid hormone at very high doses.',dose:'300–600 mg/day R-ALA; take on an empty stomach for better absorption'},
{t:'t3',n:'Pterostilbene + resveratrol combo',iN:true,tag:'Antioxidant · Longevity · Cardiovascular',e:2,s:3,r:2,o:2,c:1,d:4,desc:'Pterostilbene is four times more bioavailable than resveratrol and stays in your bloodstream longer, making the combination theoretically stronger than either compound alone. May offer better antioxidant protection for cardiovascular health and aging. However, long-term human safety data is still limited. Consider this combination experimental.',dose:'50–100 mg pterostilbene + 250–500 mg resveratrol daily; limited long-term safety data'},
{t:'t2',n:'EAAs (Essential amino acids)',iN:true,tag:'Muscle · Recovery · Fasting',e:3,s:5,r:3,o:4,c:3,d:5,desc:'Contains all nine essential amino acids your body cannot make on its own. A 2024 review found EAAs stimulate muscle protein building as effectively as whey protein but with fewer calories. Especially useful during fasting or calorie restriction when total protein intake is limited. Very safe with no serious side effects at recommended doses.',dose:'6–12 g/day around training or between meals; contains all 9 essential amino acids'},
{t:'t2',n:'Magnesium L-threonate',iN:true,tag:'Cognition · Brain magnesium · Sleep',e:3,s:5,r:2,o:2,c:2,d:5,desc:'The only form of magnesium shown to effectively cross the blood-brain barrier. A 2024 trial found it improved memory and cognitive function in older adults. Also used for sleep, though evidence for that use is still preliminary. More expensive than other magnesium forms, but may be worth it specifically for brain health goals. Very safe.',dose:'1,500–2,000 mg/day (providing ~144 mg elemental Mg); take in the evening'},
{t:'t2',n:'Spore-based probiotics (Bacillus coagulans)',iN:true,tag:'Gut health · IBS · Resilience',e:3,s:4,r:3,o:3,c:3,d:5,desc:'Spore-forming probiotics survive stomach acid and shelf storage better than traditional strains, so they don\'t need refrigeration. Bacillus coagulans has the strongest evidence among spore-based probiotics, with multiple trials showing reduced IBS symptoms and improved gut barrier function. Generally well tolerated with no major side effects.',dose:'1–2 billion CFU/day; survives stomach acid without enteric coating'},
{t:'t2',n:'Omega-3 DHA-dominant',iN:true,tag:'Brain health · Pregnancy · Cognition',e:3,s:4,r:3,o:3,c:3,d:4,desc:'Standard fish oil is EPA-dominant, but DHA is the primary structural fat in the brain and retina. DHA-focused formulas are better supported for pregnancy, infant brain development, and age-related cognitive decline. Especially important during the third trimester when fetal brain growth is fastest. Generally safe with the same profile as standard fish oil.',dose:'1,000–2,000 mg DHA/day; especially important during pregnancy and for older adults'},
{t:'t2',n:'Vitamin K1 (phylloquinone)',iN:true,tag:'Blood clotting · Bone health',e:4,s:4,r:3,o:3,c:5,d:2,desc:'The primary dietary form of vitamin K, essential for proper blood clotting and bone metabolism. Deficiency is uncommon but can occur with fat malabsorption, liver disease, or long-term antibiotic use. Works alongside vitamin D for bone health. If you take warfarin, keep your vitamin K intake consistent from day to day to avoid dose fluctuations.',dose:'90–120 mcg/day (adequate intake); caution with warfarin — dose must be consistent'},
{t:'t2',n:'Biotin (low-dose, deficiency)',iN:true,tag:'Hair · Nails · Metabolism',e:3,s:5,r:3,o:2,c:5,d:5,desc:'At physiological doses (30–100 mcg), biotin corrects true deficiency symptoms like hair loss, brittle nails, and skin rash. Different from high-dose biotin (10,000+ mcg), which lacks evidence for hair growth in non-deficient people and can falsify lab tests.',dose:'30–100 mcg/day for deficiency; stop 48 hours before blood tests to avoid interference'},
{t:'t3',n:'Pantothenic acid (Vitamin B5)',iN:true,tag:'Energy · Adrenal support · Skin',e:2,s:5,r:2,o:3,c:5,d:5,desc:'Essential for making coenzyme A, which your body needs to produce energy from food and synthesize hormones. True deficiency is extremely rare because this vitamin is found in nearly all foods. Supplementation may help with acne at higher doses, though evidence is limited. Very safe with no known upper limit for toxicity established.',dose:'5–10 mg/day (adequate intake); 500 mg+ studied for acne but evidence is limited'},
{t:'t2',n:'Manganese',iN:true,tag:'Bone health · Metabolism · Antioxidant',e:3,s:3,r:2,o:3,c:5,d:4,desc:'A trace mineral needed for bone formation, blood clotting, and antioxidant defenses. Most people get enough from diet, but supplementation may benefit bone health in postmenopausal women when combined with calcium and zinc. Do not exceed 11 mg per day because high doses cause neurotoxicity. Manganese welders and miners are at highest risk of toxicity.',dose:'1.8–2.3 mg/day (adequate intake); do not exceed 11 mg/day — neurotoxicity risk at high doses'},
{t:'t2',n:'Molybdenum',iN:true,tag:'Sulfite metabolism · Detox enzymes',e:3,s:4,r:2,o:3,c:5,d:5,desc:'An essential trace mineral required for enzymes that break down sulfites, purines, and certain drugs in your body. Deficiency is extremely rare but can cause sulfite sensitivity, which triggers headaches and breathing problems after eating certain foods. Most multivitamins contain adequate amounts. Rarely needed as a standalone supplement.',dose:'45 mcg/day (RDA); upper limit 2,000 mcg/day; rarely needed as a standalone supplement'},
{t:'t3',n:'Vanadium',iN:true,tag:'Insulin mimetic · Glucose metabolism',e:2,s:2,r:1,o:2,c:4,d:3,desc:'A trace element that mimics insulin in cell studies and may improve glucose uptake in muscle cells. However, human trials are small and short-term, and higher doses can cause stomach upset and potential kidney toxicity. Evidence is too weak to recommend for blood sugar management. Not recognized as an essential nutrient by most authorities.',dose:'10–50 mcg/day as vanadyl sulfate; evidence too weak for general recommendation'},
{t:'t3',n:'Royal jelly',iN:true,tag:'Immunity · Skin · Energy',e:2,s:3,r:2,o:2,c:2,d:3,desc:'A nutrient-rich substance produced by honeybees that contains unique proteins, sugars, and fatty acids. Small trials suggest modest effects on cholesterol and blood sugar, but study quality is generally poor. Allergic reactions are a real concern, especially in people with bee or pollen allergies. Severe reactions including anaphylaxis are possible.',dose:'300–1,000 mg/day; avoid if allergic to bee products — anaphylaxis risk'},
{t:'t3',n:'Cinnamon extract (Ceylon)',iN:true,tag:'Glucose · Insulin · Metabolic',e:2,s:4,r:3,o:2,c:4,d:3,desc:'Ceylon cinnamon is lower in coumarin, a liver-toxic compound, than the cheaper Cassia variety sold in most stores. Some trials show modest blood sugar reductions, but results are inconsistent and the actual benefit is small compared to standard treatments. Safe at recommended doses. Not effective enough to replace diabetes medication.',dose:'500–1,000 mg/day Ceylon cinnamon extract; avoid Cassia type due to coumarin content'},
{t:'t3',n:'Strontium (strontium citrate)',iN:true,tag:'Bone density · Osteoporosis',e:2,s:2,r:2,o:1,c:2,d:3,desc:'The prescription form (strontium ranelate) reduces fractures but was withdrawn in Europe due to cardiovascular risk. Over-the-counter strontium citrate lacks trial evidence and may artificially inflate bone density readings on DEXA scans, making your bones appear stronger than they are. Tell your doctor if you take strontium before getting a DEXA scan.',dose:'680 mg/day strontium citrate; inflates DEXA readings — inform your doctor if taking'},
{t:'t3',n:'Beta-sitosterol',iN:true,tag:'Prostate · Cholesterol',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A plant sterol found naturally in saw palmetto and many other plants. A Cochrane review found it modestly improves urinary symptoms in men with enlarged prostate. Also lowers bad cholesterol by blocking cholesterol absorption in the gut. Generally well tolerated with a good safety profile. May reduce absorption of some fat-soluble vitamins.',dose:'60–130 mg/day for prostate; 2,000 mg/day plant sterols for cholesterol'},
{t:'t3',n:'Cat\'s claw (Uncaria tomentosa)',iN:true,tag:'Immunity · Inflammation · Arthritis',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A South American vine used traditionally for inflammation and immunity for centuries. Small trials show modest anti-inflammatory effects in osteoarthritis, but study quality is low and sample sizes are small. May interact with blood thinners and immunosuppressant medications. Not recommended for people with autoimmune conditions without medical guidance.',dose:'250–350 mg/day standardised extract; avoid with anticoagulants or immunosuppressants'},
{t:'t3',n:'Feverfew (Tanacetum parthenium)',iN:true,tag:'Migraine prevention · Inflammation',e:2,s:3,r:3,o:2,c:3,d:3,desc:'A traditional herb for migraine prevention, but evidence is weak. A 2024 Cochrane review found only weak evidence that feverfew reduces migraine frequency when taken daily. Results are inconsistent across trials. Can cause mouth ulcers and rebound headaches if stopped abruptly. Taper gradually when discontinuing. Riboflavin is a better-supported option.',dose:'50–100 mg/day standardised to 0.2% parthenolide; taper gradually to avoid rebound'},
{t:'t3',n:'Passionflower (Passiflora incarnata)',iN:true,tag:'Anxiety · Sleep · Calm',e:2,s:4,r:2,o:4,c:3,d:4,desc:'A gentle calming herb that may help with anxiety and sleep. One trial found it comparable to the prescription drug oxazepam for anxiety, but with less mental impairment. Evidence for sleep is limited to a few small studies. Generally well tolerated with minimal side effects. May enhance the effects of sedative medications, so use caution.',dose:'250–500 mg/day extract or 1–2 cups tea; may enhance sedative medications'},
{t:'t3',n:'Skullcap (Scutellaria lateriflora)',iN:true,tag:'Anxiety · Sleep · Neuroprotection',e:2,s:3,r:1,o:4,c:3,d:3,desc:'An American herb traditionally used for anxiety and nervous tension. Very few human trials exist, and only one small study found modest anxiety reduction. Adulteration with germander, a toxic herb that causes liver damage, has been reported in some commercial products. Buy only from verified sources with third-party testing to avoid this risk.',dose:'350–500 mg/day; buy only from verified sources — adulteration risk with hepatotoxic herbs'},
{t:'t3',n:'Holy basil (Tulsi)',iN:true,tag:'Adaptogen · Stress · Glucose',e:2,s:4,r:2,o:2,c:3,d:4,desc:'A revered Ayurvedic adaptogen consumed as tea for centuries. Small trials show modest reductions in stress, blood sugar, and cholesterol, but study quality is generally low. May slow blood clotting and interact with diabetes and thyroid medications. Generally considered safe as a tea, but concentrated extracts require more caution.',dose:'300–600 mg/day extract or 2–3 cups tulsi tea; caution with blood-thinning drugs'},
{t:'t3',n:'Schisandra (Schisandra chinensis)',iN:true,tag:'Adaptogen · Liver · Endurance',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A traditional Chinese berry used for stress resilience and liver protection for over 2,000 years. Animal studies are promising, but human trial evidence is very limited. May modestly improve endurance and reduce mental fatigue. The five distinct flavors it contains (sweet, sour, salty, bitter, spicy) are unique among medicinal plants.',dose:'500–1,000 mg/day standardised extract; limited human evidence — mostly traditional use'},
{t:'t3',n:'Triphala',iN:true,tag:'Gut health · Digestion · Detox',e:2,s:4,r:2,o:3,c:4,d:4,desc:'A traditional Ayurvedic combination of three fruits (amla, bibhitaki, haritaki) used for digestive health for centuries. Small trials show modest improvements in constipation and gut transit time. Also has antioxidant properties. Generally well tolerated. Start with a low dose to assess tolerance. Evidence is mostly traditional rather than clinical.',dose:'500–1,000 mg/day or 2–4 g powder in warm water before bed; start low to assess tolerance'},
{t:'t3',n:'Olive oil extract (hydroxytyrosol)',iN:true,tag:'Cardiovascular · Antioxidant',e:2,s:5,r:2,o:2,c:3,d:5,desc:'Hydroxytyrosol is the main antioxidant in extra virgin olive oil and one of the most potent natural antioxidants studied. EFSA approved a health claim for olive oil polyphenols protecting blood lipids from oxidation. Supplement evidence is more limited than dietary olive oil evidence. Simply using extra virgin olive oil in cooking may be equally effective.',dose:'5–20 mg/day hydroxytyrosol; EFSA claim requires 5 mg/day from olive oil or extracts'},
{t:'t3',n:'Pygeum africanum',iN:true,tag:'Prostate · Urinary health',e:2,s:4,r:2,o:2,c:3,d:4,desc:'African cherry tree bark extract used for prostate health in Europe for decades. A Cochrane review found it modestly improves urinary symptoms in men with enlarged prostate, but overall trial quality was generally low. Evidence is modest but consistent across studies. Generally well tolerated with few side effects at recommended doses.',dose:'100–200 mg/day standardised extract (14% triterpenes); evidence modest but consistent'},
{t:'t3',n:'Black garlic extract',iN:true,tag:'Cardiovascular · Antioxidant',e:2,s:5,r:2,o:2,c:3,d:5,desc:'Regular garlic aged through a controlled heat and humidity process that converts harsh sulfur compounds into gentler, more concentrated antioxidants. Small trials show modest improvements in cholesterol and blood pressure, with significantly less odor and fewer digestive side effects than raw garlic. Generally very safe and well tolerated.',dose:'600–1,500 mg/day aged black garlic extract; fewer GI side effects than raw garlic'},
{t:'t3',n:'Gotu kola (Centella asiatica)',iN:true,tag:'Cognition · Wound healing · Anxiety',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A traditional Ayurvedic herb used for mental clarity and skin healing. Small trials show it may improve cognitive function in elderly adults and speed wound healing when applied topically. Evidence is preliminary and study quality is generally low. May cause liver injury at high doses. Not to be confused with kola nut, which contains caffeine.',dose:'250–500 mg/day standardised extract (10% asiaticoside); may cause liver injury at high doses'},
{t:'t3',n:'Shatavari (Asparagus racemosus)',iN:true,tag:'Female health · Lactation · Adaptogen',e:2,s:4,r:2,o:2,c:3,d:4,desc:'An Ayurvedic herb traditionally used for women\'s reproductive health. Small trials suggest it may increase breast milk production and support hormonal balance throughout different life stages. Human evidence from clinical trials is still limited, with most support coming from traditional use. Generally well tolerated with a good safety profile.',dose:'500–1,000 mg/day root extract; traditional use for lactation and female hormone support'},
{t:'t3',n:'Lycopene',iN:true,tag:'Prostate · Cardiovascular · Skin',e:2,s:5,r:3,o:2,c:3,d:5,desc:'The red pigment in tomatoes that acts as a powerful antioxidant. A 2024 review found men with the highest lycopene intake had significantly lower prostate cancer risk. Also shows modest benefits for blood pressure and skin sun protection. Best absorbed from cooked tomatoes or supplements taken with a fat source. Very safe at recommended doses.',dose:'10–30 mg/day; better absorbed from cooked tomatoes or supplements taken with a fat source'},
{t:'t3',n:'Silica (orthosilicic acid)',iN:true,tag:'Bone · Hair · Nails · Collagen',e:2,s:4,r:2,o:1,c:3,d:5,desc:'Silicon is involved in collagen synthesis and bone mineralization, playing a supporting role in connective tissue health. A few trials show modest improvements in hair thickness and nail brittleness. The liquid orthosilicic acid form is better absorbed than solid silica supplements. Generally safe. Evidence is modest but growing for hair and nail benefits.',dose:'5–10 mg/day orthosilicic acid (liquid form); solid silica is poorly absorbed'},
{t:'t3',n:'MCT oil (medium chain triglycerides)',iN:true,tag:'Energy · Ketosis · Cognition',e:2,s:4,r:2,o:5,c:3,d:5,desc:'Medium chain fats that bypass normal digestion and go straight to the liver for quick energy or ketone production. Useful for people on ketogenic diets and may provide short-term cognitive fuel through ketone bodies. Can cause stomach upset if introduced too fast. Start with just 5 mL per day and increase gradually over 1 to 2 weeks.',dose:'5–15 mL/day; start with 5 mL to avoid GI distress; ramp up gradually over 1–2 weeks'},
{t:'t3',n:'Phosphoric acid (urinary)',iN:true,tag:'Kidney stones · Urinary acidification',e:1,s:3,r:1,o:4,c:4,d:3,desc:'Sometimes used in folk medicine to dissolve calcium-based kidney stones, but no clinical trial supports this claim. May actually worsen kidney stone risk by disrupting the calcium and phosphorus balance in your body. Not recommended as a supplement by any medical authority. If you have kidney stones, consult a urologist for evidence-based treatment.',dose:'No evidence-based dose; may worsen kidney stone risk — not recommended as a supplement'},
{t:'t3',n:'Activated B complex (methylated)',iN:true,tag:'Energy · Mood · Methylation',e:2,s:4,r:2,o:3,c:3,d:4,desc:'A B-complex formula using pre-methylated forms (methylfolate, methylcobalamin, P5P) that bypass genetic variations in the MTHFR enzyme. May benefit people with confirmed MTHFR mutations and elevated homocysteine, but most healthy adults process standard B vitamins just fine without needing the more expensive methylated versions.',dose:'1 capsule/day providing methylated B12, folate, and B6 (P5P); most useful with confirmed MTHFR variants'},
{t:'t4',n:'Greater celandine (Chelidonium majus)',iN:true,tag:'Liver toxicity · Hepatitis',e:1,s:1,r:1,o:2,c:1,d:1,desc:'A European herb once used for digestive complaints that turned out to be dangerous. Multiple case reports of serious liver damage including hepatitis and acute liver failure have been documented. Banned or restricted in several countries including Germany. No proven therapeutic benefit justifies the serious liver damage risk it carries.',dose:'AVOID — multiple reports of severe hepatotoxicity; no demonstrated benefit'},
{t:'t4',n:'Black cohosh high-dose',iN:true,tag:'Liver damage · Menopause',e:2,s:1,r:2,o:2,c:2,d:2,desc:'At standard doses of 20 to 40 mg per day, black cohosh may modestly relieve hot flashes. However, high doses above 160 mg per day and prolonged use have been linked to rare but serious liver injury, including cases requiring liver transplant. If you use the standard dose form, liver function monitoring is recommended during treatment.',dose:'AVOID high doses (>160 mg/day) or prolonged use; standard dose 20–40 mg/day requires liver monitoring'},
{t:'t4',n:'Licorice root high-dose',iN:true,tag:'Hypokalemia · Hypertension · Cardiac',e:2,s:1,r:2,o:3,c:3,d:1,desc:'Contains glycyrrhizin, which blocks cortisol breakdown and causes your body to retain sodium and lose potassium. This can lead to dangerously high blood pressure, low potassium, and heart rhythm problems, even from amounts found in licorice candy. The DGL form (with glycyrrhizin removed) is much safer for stomach use.',dose:'AVOID >50 mg glycyrrhizin/day; DGL licorice (glycyrrhizin removed) is safer for stomach use'},
{t:'t4',n:'Bitter orange (Citrus aurantium)',iN:true,tag:'Cardiovascular risk · Synephrine',e:2,s:1,r:2,o:5,c:2,d:1,desc:'Contains synephrine, a stimulant similar to the banned substance ephedra. Marketed for weight loss and energy, but associated with heart attacks, strokes, and dangerous blood pressure spikes. The risk increases significantly when combined with caffeine, which many people do unknowingly. Has caused multiple serious cardiac events in otherwise healthy adults.',dose:'AVOID — cardiovascular risk similar to banned ephedra; especially dangerous with caffeine'},
{t:'t4',n:'Androstenedione (prohormone)',iN:true,tag:'Banned · Liver toxicity · Hormonal',e:2,s:1,r:1,o:3,c:1,d:1,desc:'A testosterone precursor banned by the FDA and most sports organizations. Despite marketing claims, it does not reliably increase testosterone but does increase estrogen levels in men. Associated with liver damage, acne, and hormonal disruption. Classified as a controlled substance. There is no legitimate reason to use this supplement.',dose:'AVOID — banned substance; increases estrogen, not testosterone; liver toxicity risk'},
{t:'t4',n:'1,3-DMBA (dimethylbutylamine)',iN:true,tag:'Stimulant · Cardiovascular · Seizure',e:1,s:1,r:1,o:5,c:1,d:1,desc:'A synthetic stimulant found in some pre-workout and weight loss products sold online and in retail stores. FDA has warned it is not a legitimate dietary ingredient and has no place in supplements. Linked to cardiovascular emergencies, seizures, and at least one death. Check product labels carefully before purchasing any pre-workout supplement.',dose:'AVOID — not a dietary ingredient; FDA-warned; linked to cardiac events and seizures'},
{t:'t4',n:'Methyl-1-testosterone (oral steroid)',iN:true,tag:'Liver failure · Illegal · Hormonal',e:2,s:1,r:1,o:3,c:1,d:1,desc:'An oral anabolic steroid illegally sold as a supplement in some online marketplaces. Extremely toxic to the liver, with multiple cases of acute liver failure and death reported. Banned under the Anabolic Steroid Control Act. Possessing or selling this compound is a federal crime. No legitimate supplement should contain this ingredient.',dose:'AVOID — illegal anabolic steroid; causes severe liver damage and hormonal disruption'},
{t:'t4',n:'Phenibut',iN:true,tag:'GABAergic · Dependence · Withdrawal',e:2,s:1,r:1,o:4,c:2,d:1,desc:'A synthetic compound developed in Russia that produces calming and euphoric effects. Causes rapid physical dependence, often within just days to weeks of regular use. Withdrawal can be severe and life-threatening, resembling benzodiazepine or alcohol withdrawal with seizure risk. Not approved as a supplement in the US, EU, or Australia.',dose:'AVOID — rapid physical dependence; withdrawal seizures; not approved in the US, EU, or Australia'},
{t:'t4',n:'Yohimbe bark (Pausinystalia yohimbe)',iN:true,tag:'Cardiac arrhythmia · Hypertensive crisis',e:2,s:1,r:1,o:4,c:1,d:1,desc:'Contains yohimbine, a potent stimulant compound that affects the heart and nervous system. Multiple reports of dangerous blood pressure spikes, heart attacks, and seizures have been linked to yohimbe bark supplements. FDA notes that supplement products are completely unregulated for actual yohimbine content, so doses are unpredictable and dangerous.',dose:'AVOID supplement-form yohimbe bark — prescription yohimbine HCl only under medical supervision'},
{t:'t2',n:'Monolaurin',iN:true,tag:'Antimicrobial · Immunity · Gut',e:2,s:4,r:2,o:3,c:3,d:5,desc:'A coconut-derived compound with strong antimicrobial activity against viruses and bacteria in lab studies. Limited human trials exist, and most evidence is extrapolated from studies on lauric acid found in coconut oil. Start with a low dose to avoid digestive discomfort. Generally considered safe, but clinical evidence for specific conditions is lacking.',dose:'600–1,800 mg/day; start low (300 mg) to avoid Herxheimer-like reactions'},
{t:'t2',n:'Dihydromyricetin (DHM)',iN:true,tag:'Liver protection · Alcohol metabolism · Hangover',e:2,s:4,r:2,o:4,c:3,d:5,desc:'A plant compound from the Japanese raisin tree that helps your body process alcohol faster. A 2024 trial found 600 mg significantly reduced hangover symptoms and the toxic alcohol byproduct acetaldehyde the next morning. Works by boosting your body\'s alcohol-processing enzymes. Generally well tolerated. Not a license to drink excessively.',dose:'300–600 mg before or during alcohol consumption'},
{t:'t3',n:'Pregnenolone',iN:true,tag:'Hormonal · Cognition · Mood',e:2,s:2,r:2,o:2,c:2,d:2,desc:'A precursor hormone your body uses to make cortisol, DHEA, progesterone, and testosterone. No high-quality trials support the cognitive or mood benefits sometimes claimed. Can disrupt hormonal balance and cause unwanted side effects. Requires regular hormone panel monitoring by your doctor. Not recommended for healthy adults without medical guidance.',dose:'10–30 mg/day if clinically indicated; not recommended without hormone panel monitoring'},
{t:'t3',n:'Shoden ashwagandha (high-withanolide)',iN:true,tag:'Sleep · Stress · High-potency variant',e:2,s:3,r:2,o:2,c:2,d:3,desc:'An ultra-concentrated ashwagandha extract that is about 7 times more potent than the standard KSM-66 form. A single 2024 trial found 120 mg improved sleep quality, but only one study has been completed so far. Has less long-term safety data than KSM-66. The standard form has a much stronger evidence base. Use conservatively with cycling.',dose:'120 mg/day Shoden extract; less long-term safety data than KSM-66 — cycle conservatively'},
{t:'t3',n:'Humic acid',iN:true,tag:'Mineral transport · Detox claims · Gut',e:1,s:3,r:1,o:3,c:1,d:4,desc:'A soil-derived compound often sold alongside fulvic acid and marketed for gut health and mineral absorption. No human trial evidence supports any health claim. Heavy metal contamination is a documented risk with these products. Not recognized as safe or effective by any major health authority. Your money is better spent on supplements with clinical evidence.',dose:'No evidence-based dose; contamination risk; not recommended'},
{t:'t3',n:'Collagen type II (undenatured, UC-II)',iN:true,tag:'Joint · Autoimmune · Cartilage',e:2,s:4,r:2,o:1,c:3,d:5,desc:'Different from regular collagen peptides. This works by training your immune system to stop attacking joint cartilage, not by supplying collagen directly. A 2024 review of 5 trials found 40 mg per day significantly reduced arthritis joint pain. Take on an empty stomach for best results. Very safe with no notable side effects reported in studies.',dose:'40 mg/day undenatured type II collagen (UC-II) on empty stomach; distinct mechanism from collagen peptides'},
{t:'t4',n:'Aconite (Aconitum napellus)',iN:true,tag:'Cardiac arrest · Neurotoxicity · Fatal',e:1,s:1,r:1,o:5,c:1,d:1,desc:'One of the most toxic plants on Earth. The lethal dose can be as low as 2 mg, meaning even trace amounts can kill. Multiple deaths from traditional medicine preparations have been documented worldwide. There is no antidote. WHO says there is no safe medicinal use. Death occurs through cardiac arrest and respiratory paralysis.',dose:'AVOID — no safe dose; rapidly fatal via cardiac arrhythmia and respiratory paralysis'},
{t:'t4',n:'Calomel (mercurous chloride)',iN:true,tag:'Mercury poisoning · Nephrotoxicity',e:1,s:1,r:1,o:3,c:1,d:1,desc:'A mercury compound still found in some traditional Ayurvedic and Chinese medicine products today. Causes irreversible kidney damage, brain damage, and death even at low doses. FDA banned it from over-the-counter drugs. Mercury accumulates in the body over time. Always check traditional herbal products for mercury content before using them.',dose:'AVOID — contains mercury; no safe dose for any purpose'},
{t:'t4',n:'Comfrey (Symphytum officinale, oral)',iN:true,tag:'Hepatotoxicity · Pyrrolizidine alkaloids',e:1,s:1,r:1,o:3,c:1,d:1,desc:'Contains toxic compounds called pyrrolizidine alkaloids that cause liver vein blockage disease, a serious and potentially fatal condition. FDA, European, and Australian authorities all advise against oral use. Multiple cases of liver failure have been reported. Topical application for musculoskeletal pain is the only acceptable use.',dose:'AVOID oral use entirely — topical application only for musculoskeletal pain'},
{t:'t4',n:'Pennyroyal oil (Mentha pulegium)',iN:true,tag:'Abortifacient · Hepatotoxicity · Fatal',e:1,s:1,r:1,o:4,c:1,d:1,desc:'Contains pulegone, which the body converts into a liver-toxic compound through normal metabolism. Multiple documented deaths from oral ingestion have been reported, with lethal doses as low as 10 mL of the essential oil. Historically misused as an herbal remedy. No therapeutic benefit whatsoever. There is no safe dose for internal use.',dose:'AVOID — lethal at doses as low as 10 mL of essential oil'},
{t:'t4',n:'Colloidal gold',iN:true,tag:'No evidence · Pseudoscience',e:1,s:2,r:1,o:3,c:1,d:4,desc:'No known mechanism of action, no trial evidence, and gold has no biological role in the human body whatsoever. FDA does not recognize it as safe or effective for any medical purpose. Sometimes marketed with pseudoscientific claims about "cellular energy" or "detox." There is no reason to consume gold as a supplement. Save your money entirely.',dose:'AVOID — no evidence of benefit; unknown long-term safety'},
{t:'t4',n:'Cesium chloride (alkaline therapy)',iN:true,tag:'Cardiac arrest · Pseudoscience',e:1,s:1,r:1,o:3,c:1,d:1,desc:'Marketed as "alkaline cancer therapy," but this concept has no scientific basis. Multiple reports of fatal heart rhythm disturbances have been linked to cesium chloride use. FDA has issued a formal warning against it. No trial evidence supports any benefit whatsoever. The risk of sudden cardiac death makes this one of the most dangerous supplements sold.',dose:'AVOID — risk of fatal cardiac arrhythmia; no therapeutic benefit'},
{t:'t4',n:'Germander (Teucrium chamaedrys)',iN:true,tag:'Hepatotoxicity · Banned herb',e:1,s:1,r:1,o:3,c:1,d:1,desc:'Banned in France since 1992 after multiple cases of hepatitis and liver failure. Contains compounds that the body converts into liver-damaging toxins through normal metabolism. No therapeutic benefit has been demonstrated in clinical trials. Still occasionally found in some herbal blends and traditional formulations. Check ingredient lists carefully.',dose:'AVOID entirely — banned in multiple countries due to liver toxicity'},
{t:'t4',n:'SARMs (Selective Androgen Receptor Modulators)',iN:true,tag:'Unlicensed anabolics',e:2,s:1,r:1,o:3,c:1,d:1,desc:'Unapproved pharmaceutical drugs illegally sold as supplements, primarily marketed to gym-goers as "legal steroids." Multiple cases of liver failure, heart attacks, and strokes have been reported from their use. Not approved for human use by the FDA or any major health authority. Products may contain undisclosed or contaminated ingredients. Avoid entirely.',dose:'AVOID entirely — not approved for human use as a dietary supplement'},
{t:'t4',n:'DNP (2,4-Dinitrophenol)',iN:true,tag:'Fatal hyperthermia · Metabolic uncoupling',e:2,s:1,r:1,o:4,c:1,d:1,desc:'An industrial chemical that causes about 1 to 2 deaths per year in the UK alone. It works by generating dangerous amounts of heat inside your body, which can be fatal. There is no safe dose and no antidote if you take too much. WHO says DNP has no legitimate medicinal or supplement use. Sold illegally online for weight loss. Avoid entirely.',dose:'AVOID — no safe dose. No antidote.'},
{t:'t1',n:'Fibre (general dietary)',iN:true,tag:'Gut · Heart · Glucose',e:4,s:5,r:5,o:3,c:5,d:5,desc:'Dietary fibre is one of the most consistently supported nutrients in nutrition science. Large reviews show it lowers heart disease risk, improves blood sugar control, and feeds the beneficial bacteria in your gut. Most adults only get about half the recommended intake from food alone. Soluble fibre (oats, psyllium) lowers cholesterol while insoluble fibre (bran, vegetables) supports regularity.',dose:'25–30 g/day total from food and supplements; increase gradually to avoid bloating'},
{t:'t1',n:'Sodium bicarbonate (sports)',iN:true,tag:'Buffering · Endurance · Sprint',e:4,s:4,r:4,o:5,c:5,d:4,desc:'Buffers lactic acid buildup during intense exercise, allowing you to push harder for longer. A 2024 review of 40 trials confirmed it meaningfully improves sprint and high-intensity performance lasting 30 seconds to 12 minutes. Take 60 to 90 minutes before exercise with plenty of water. Stomach discomfort is the main side effect, which can be reduced by splitting the dose or using enteric-coated capsules.',dose:'0.2–0.3 g/kg body weight 60–90 min before exercise; split dose or use capsules to reduce GI distress'},
{t:'t2',n:'Baicalin (Scutellaria baicalensis)',iN:true,tag:'Inflammation · Neuroprotection · Liver',e:3,s:4,r:2,o:2,c:3,d:4,desc:'A flavonoid from Chinese skullcap with strong anti-inflammatory and neuroprotective effects in lab studies. Early human trials show it may help reduce liver inflammation and protect brain cells from oxidative damage. Clinical evidence in humans is still limited, with most data coming from cell and animal research. Generally well tolerated at standard doses.',dose:'250–500 mg/day standardised extract; human trial evidence still limited'},
{t:'t2',n:'Beta-glucan (1,3/1,6)',iN:true,tag:'Immunity · Cholesterol',e:3,s:5,r:3,o:3,c:3,d:5,desc:'A natural fibre found in oats, barley, and certain mushrooms that supports immune function and lowers cholesterol. EFSA approved a health claim for oat beta-glucan reducing cholesterol at 3 g per day. The yeast-derived 1,3/1,6 form has the strongest evidence for immune activation. Very safe with no serious side effects reported in studies.',dose:'250–500 mg/day yeast beta-glucan for immunity; 3 g/day oat beta-glucan for cholesterol'},
{t:'t2',n:'Caprylic acid (C8 MCT)',iN:true,tag:'Ketosis · Energy · Cognition',e:3,s:4,r:2,o:5,c:3,d:5,desc:'The most ketogenic medium-chain fatty acid, converting to brain-fuelling ketones faster than standard MCT oil. Popular among people following ketogenic diets for sustained mental energy without carbohydrates. Can cause stomach upset if introduced too quickly. Start with a small dose and increase gradually over one to two weeks. Generally safe at moderate doses.',dose:'5–15 mL/day pure C8 MCT oil; start with 5 mL to avoid GI distress'},
{t:'t2',n:'Chlorogenic acid (green coffee)',iN:true,tag:'Glucose · Blood pressure',e:3,s:4,r:3,o:2,c:3,d:4,desc:'The main active compound in green coffee bean extract, shown to modestly lower blood sugar and blood pressure in multiple trials. Works by slowing glucose absorption in the gut and improving how your body handles sugar after meals. Contains less caffeine than roasted coffee. Generally well tolerated with mild digestive effects in some people.',dose:'200–400 mg/day chlorogenic acid (equivalent to 400–800 mg green coffee extract)'},
{t:'t2',n:'DHA (standalone, algal)',iN:true,tag:'Brain · Pregnancy · Vegan',e:4,s:5,r:3,o:3,c:2,d:4,desc:'The primary structural omega-3 fat in the brain and retina, sourced from algae instead of fish. Provides the same DHA found in fish oil but is suitable for vegans and vegetarians. Especially important during pregnancy for fetal brain development. Algal DHA is sustainably produced and free from ocean pollutants like mercury and PCBs. Very safe at recommended doses.',dose:'200–1,000 mg/day algal DHA; especially important for vegans and during pregnancy'},
{t:'t2',n:'Ecklonia cava (brown seaweed)',iN:true,tag:'Circulation · Sleep · Inflammation',e:2,s:4,r:2,o:2,c:2,d:5,desc:'A brown seaweed extract from the coast of Korea and Japan containing unique polyphenols called phlorotannins. Small trials show modest improvements in blood circulation, sleep quality, and inflammation markers. Research is still in early stages with relatively few human studies completed. Generally well tolerated with no serious side effects reported.',dose:'72–144 mg/day standardised extract; human evidence still limited'},
{t:'t2',n:'Elderberry + Zinc combo',iN:true,tag:'Cold/Flu · Immunity',e:3,s:4,r:2,o:4,c:3,d:5,desc:'Combines two ingredients with individual evidence for shortening colds. Elderberry reduces cold duration by 2 to 4 days and zinc lozenges shorten colds by about 2 days when started early. The combination is popular in cold and flu products, though no trials have tested whether the pair works better than either ingredient alone. Both are well tolerated.',dose:'15 mL elderberry syrup + 15–30 mg zinc per day at first signs of illness for 3–5 days'},
{t:'t2',n:'Hesperidin',iN:true,tag:'Circulation · Venous insufficiency',e:3,s:5,r:2,o:2,c:3,d:5,desc:'A citrus flavonoid found naturally in oranges and lemons that supports healthy blood vessel function. Multiple European trials show it significantly improves symptoms of chronic venous insufficiency including leg heaviness, swelling, and cramps. Commonly combined with diosmin in products sold throughout Europe for vein health. Very safe with no serious side effects.',dose:'500 mg/day hesperidin or 900 mg/day diosmin-hesperidin complex'},
{t:'t2',n:'IP-6 (Inositol hexaphosphate)',iN:true,tag:'Immunity · Cancer adjunct',e:2,s:4,r:2,o:2,c:3,d:5,desc:'A naturally occurring compound found in grains and legumes that may support immune function. Lab studies show it enhances natural killer cell activity, and small clinical trials suggest possible benefits as an adjunct alongside conventional cancer treatment. Human evidence is still limited and more research is needed. Generally well tolerated at standard doses.',dose:'1–8 g/day in divided doses on an empty stomach; evidence mostly preclinical'},
{t:'t2',n:'Kudzu (Pueraria lobata)',iN:true,tag:'Alcohol reduction · Cardiovascular',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A traditional Chinese herb that may help reduce heavy drinking. A Harvard pilot study found kudzu root extract significantly reduced the number of drinks consumed per session without causing unpleasant side effects. Contains isoflavones that interact with dopamine pathways involved in reward and craving. Limited human trial data overall.',dose:'1,500–2,000 mg/day standardised extract (40% isoflavones); limited human evidence'},
{t:'t2',n:'N-Acetyl glucosamine',iN:true,tag:'Gut barrier · IBD · Joint',e:3,s:5,r:2,o:3,c:3,d:5,desc:'A building block of the mucus layer that protects your gut lining. Different from regular glucosamine used for joints, this form specifically supports the gut barrier. Small trials in inflammatory bowel disease showed improved gut lining integrity. Also plays a role in joint cartilage maintenance. Very safe with no serious side effects reported in studies.',dose:'500–1,500 mg/day; different from glucosamine sulfate used for joint pain'},
{t:'t2',n:'Oleuropein (olive extract)',iN:true,tag:'Cardiovascular · Antiviral',e:3,s:4,r:2,o:2,c:3,d:4,desc:'The primary active compound in olive leaf extract responsible for its heart-protective effects. Trials show it helps lower blood pressure and improves blood vessel function. Lab studies confirm antiviral and antimicrobial activity. Related to but more concentrated than what you get from eating olives or olive oil. Generally well tolerated at standard doses.',dose:'250–500 mg/day oleuropein from standardised olive leaf extract'},
{t:'t2',n:'Rutin',iN:true,tag:'Circulation · Varicose veins · Inflammation',e:3,s:5,r:2,o:2,c:4,d:5,desc:'A plant flavonoid found in buckwheat, citrus fruits, and asparagus that strengthens blood vessel walls. Multiple European trials show it significantly reduces leg swelling and symptoms of chronic venous insufficiency. Works through anti-inflammatory pathways and by reducing capillary permeability. Very safe with an excellent tolerance profile and no serious side effects.',dose:'500–1,000 mg/day; often combined with hesperidin and vitamin C for vascular support'},
{t:'t2',n:'Tocotrienols (vitamin E fraction)',iN:true,tag:'Cardiovascular · Skin · Neuroprotection',e:2,s:4,r:2,o:2,c:2,d:4,desc:'A less common but potentially more potent form of vitamin E found in palm fruit, rice bran, and annatto. Emerging research suggests tocotrienols may protect the brain and heart through pathways distinct from regular vitamin E. Human evidence is still growing, with promising but preliminary results. Generally safe at recommended doses.',dose:'100–300 mg/day mixed tocotrienols from annatto or palm; take with a fatty meal'},
{t:'t2',n:'Zinc carnosine',iN:true,tag:'Gut barrier · H. pylori · Ulcer',e:3,s:5,r:3,o:3,c:3,d:5,desc:'A unique compound that combines zinc and carnosine in a chelated form designed to stick to the stomach lining where it is needed most. Approved in Japan as a treatment for stomach ulcers. Multiple trials show it helps repair gut barrier damage, reduce H. pylori infection alongside antibiotics, and protect the stomach from NSAID damage. Very safe.',dose:'75 mg zinc carnosine twice daily before meals; approved for gastric ulcers in Japan'},
{t:'t3',n:'Bamboo extract (silica)',iN:true,tag:'Hair · Nails · Bone',e:1,s:4,r:1,o:1,c:3,d:5,desc:'A plant source of organic silica marketed for hair, nail, and bone health. Contains higher silica concentrations than horsetail extract. However, very few human trials have tested bamboo extract specifically, and most claims are based on theoretical benefits of silica rather than direct evidence. Generally safe with no serious side effects reported.',dose:'200–400 mg/day bamboo extract (70% silica); human trial evidence lacking'},
{t:'t3',n:'Blue-green algae (AFA)',iN:true,tag:'Cognition · Energy claims',e:1,s:2,r:1,o:3,c:2,d:4,desc:'Aphanizomenon flos-aquae is a type of cyanobacteria harvested from lakes and sold as a superfood. Marketing claims about brain health and energy lack clinical evidence. Contamination with microcystins, which are potent liver toxins, is a real concern because wild-harvested products depend entirely on lake water quality. Not recommended.',dose:'No evidence-based dose; microcystin contamination risk from wild-harvested sources'},
{t:'t4',n:'Borax (boron supplement form)',iN:true,tag:'Joint · Hormone claims',e:1,s:2,r:1,o:3,c:4,d:3,desc:'Sometimes promoted online as a cheap boron supplement for joint health and hormone balance. Borax is a cleaning product, not a dietary supplement, and is banned as a food additive in the US, EU, and Australia. The boron content is poorly controlled and high doses cause reproductive and kidney toxicity. Use boron glycinate instead if supplementing boron.',dose:'AVOID borax as a supplement; use boron glycinate (3–6 mg/day) for boron supplementation'},
{t:'t3',n:'Calcium D-glucarate',iN:true,tag:'Estrogen metabolism · Detox',e:2,s:4,r:1,o:2,c:3,d:4,desc:'Supports the body\'s natural detoxification process by inhibiting an enzyme called beta-glucuronidase. Theoretically helps your body clear excess estrogen more efficiently. Lab and animal studies are promising, but human clinical trials are essentially nonexistent. Generally considered safe at standard doses. Sometimes used alongside DIM for hormone support.',dose:'200–500 mg/day; no human clinical trials — evidence is theoretical and preclinical'},
{t:'t3',n:'Cistus incanus',iN:true,tag:'Immunity · Antiviral · Biofilm',e:2,s:4,r:1,o:2,c:3,d:5,desc:'A Mediterranean shrub traditionally used as tea for immune support. Lab studies show strong antiviral activity and the ability to disrupt bacterial biofilms. One small German trial found it reduced cold symptoms, but the study was industry-funded and has not been replicated. More human research is needed before it can be recommended with confidence.',dose:'500–1,500 mg/day extract or 2–3 cups cistus tea; very limited human trial data'},
{t:'t3',n:'Colloidal minerals',iN:true,tag:'Mineral absorption claims',e:1,s:3,r:1,o:3,c:2,d:4,desc:'Liquid mineral products sourced from ancient plant deposits or clay, marketed as being more absorbable than standard mineral supplements. No clinical evidence supports superior absorption or any health benefit over conventional mineral forms. Mineral content and purity vary widely between products. Some products have tested positive for heavy metal contamination.',dose:'No evidence-based dose; unregulated content; contamination risk from unverified sources'},
{t:'t3',n:'Deer antler velvet',iN:true,tag:'IGF-1 · Athletic claims',e:1,s:3,r:1,o:2,c:1,d:3,desc:'Harvested from the soft cartilage of growing deer antlers and marketed for athletic performance and IGF-1 boosting. Multiple controlled trials found no significant improvement in strength, endurance, or testosterone levels in healthy adults. The IGF-1 content in supplements is too low to meaningfully affect blood levels. Not recommended for athletic use.',dose:'500–1,500 mg/day; no meaningful performance benefit demonstrated in controlled trials'},
{t:'t3',n:'Digestive bitters',iN:true,tag:'Digestion · Appetite · Bile',e:2,s:4,r:1,o:4,c:4,d:4,desc:'Herbal extracts of bitter-tasting plants like gentian, dandelion, and artichoke that stimulate digestive secretions through taste receptors on the tongue. Traditional use across many cultures supports their role in improving appetite and digestion. Modern clinical evidence is very limited. Generally well tolerated and widely available as tinctures and capsules.',dose:'1–2 mL tincture or 500 mg capsule 15–30 min before meals; evidence mostly traditional'},
{t:'t3',n:'Emu oil (oral)',iN:true,tag:'Inflammation · Gut',e:1,s:3,r:1,o:2,c:2,d:5,desc:'An oil rendered from emu fat that contains a unique fatty acid profile with anti-inflammatory properties. Topical use for skin inflammation has modest evidence, but oral supplementation for gut health and systemic inflammation has very little human research. Animal studies show some promise for reducing gut inflammation. Generally well tolerated.',dose:'1–2 g/day oral emu oil capsules; human evidence for oral use is extremely limited'},
{t:'t3',n:'Fucoidan',iN:true,tag:'Cancer adjunct · Immunity',e:2,s:4,r:1,o:2,c:2,d:5,desc:'A complex sugar found in brown seaweed with immune-stimulating and anticancer properties in lab studies. Small human trials in cancer patients show improved immune markers when used alongside conventional treatment. Most evidence comes from cell and animal research rather than rigorous human trials. Generally well tolerated with no serious side effects.',dose:'500–1,000 mg/day from Undaria or Fucus seaweed; most evidence is preclinical'},
{t:'t3',n:'Glutathione precursors blend',iN:true,tag:'Antioxidant · Detox',e:2,s:4,r:2,o:2,c:2,d:5,desc:'Combines NAC, glycine, and selenium to provide your body with the raw materials needed to produce glutathione, its master antioxidant. This approach may be more effective and affordable than taking glutathione directly, since oral glutathione is poorly absorbed. Each ingredient has independent evidence supporting antioxidant and detox pathways.',dose:'600 mg NAC + 3 g glycine + 100 mcg selenium daily; may be more effective than direct glutathione'},
{t:'t3',n:'HMB + Creatine stack',iN:true,tag:'Muscle · Sarcopenia combo',e:2,s:5,r:2,o:3,c:3,d:5,desc:'Combines two supplements with independent evidence for preserving muscle mass in older adults. Creatine is one of the best-studied supplements for strength and HMB helps prevent muscle breakdown. No trials have tested whether the combination provides extra benefit beyond either supplement alone. Both are individually very safe with excellent track records.',dose:'3 g HMB + 5 g creatine monohydrate daily; combination not specifically validated in trials'},
{t:'t3',n:'Jiaogulan (Gynostemma)',iN:true,tag:'Adaptogen · Cholesterol',e:2,s:3,r:1,o:2,c:3,d:3,desc:'A climbing vine from Southeast Asia sometimes called "Southern ginseng" because it contains compounds similar to ginsenosides. Small trials show modest reductions in cholesterol and blood sugar. Traditional use as an adaptogenic tea spans centuries. Human research is limited and mostly from small studies. May interact with blood thinners and diabetes medications.',dose:'450–900 mg/day extract or 3 cups gynostemma tea; limited human trial data'},
{t:'t3',n:'K2 + D3 combo',iN:true,tag:'Bone · Cardiovascular stack',e:2,s:5,r:2,o:3,c:4,d:3,desc:'Vitamin D3 helps your body absorb calcium while K2 directs that calcium into bones and away from arteries. Both have individual evidence for bone and heart health, and the combination makes biological sense. However, few trials have tested the specific combination versus each vitamin alone. Both are safe individually and widely available together.',dose:'1,000–2,000 IU D3 + 100–200 mcg K2 (MK-7) daily; combination logic is sound but not directly validated'},
{t:'t3',n:'Lacto-fermented foods (supplement form)',iN:true,tag:'Gut · Immunity',e:2,s:5,r:2,o:3,c:4,d:5,desc:'Capsulised versions of fermented foods like sauerkraut, kimchi, and kefir that provide both probiotics and their metabolic byproducts called postbiotics. Eating actual fermented foods is better studied and less expensive than supplements. A 2024 Stanford study found fermented foods significantly increased gut bacteria diversity more than high-fibre diets. Very safe.',dose:'1–2 capsules/day; eating actual fermented foods (sauerkraut, kefir, kimchi) is preferred and better studied'},
{t:'t3',n:'Milk peptides (casein hydrolysate)',iN:true,tag:'Sleep · Anxiety · Blood pressure',e:2,s:5,r:2,o:4,c:2,d:5,desc:'Specific peptides derived from milk protein that have calming effects on the nervous system. The Lactium brand (alpha-s1 casein tryptic hydrolysate) has the most research, showing reduced stress and improved sleep quality in several trials. Works through GABA-related calming pathways. Very safe with no dependency risk. Takes about 2 weeks for full effect.',dose:'150–300 mg/day Lactium (alpha-s1 casein hydrolysate); allow 2 weeks for full effect'},
{t:'t3',n:'N-Acetyl Tyrosine (NALT)',iN:true,tag:'Focus · Stress resilience',e:2,s:5,r:2,o:4,c:3,d:5,desc:'An acetylated form of L-tyrosine marketed as more water-soluble and better absorbed. However, research suggests your body may actually convert NALT back to tyrosine less efficiently than regular L-tyrosine. The standard L-tyrosine form has more clinical evidence and is generally preferred by researchers. Very safe with no serious side effects.',dose:'300–600 mg/day NALT; standard L-tyrosine (500–2,000 mg) is generally preferred for efficacy'},
{t:'t3',n:'Oil of oregano (soft gel)',iN:true,tag:'Antimicrobial · Gut · SIBO',e:2,s:3,r:1,o:4,c:3,d:3,desc:'Enteric-coated soft gels designed to deliver oregano oil to the small intestine for gut infections and SIBO. The active compound carvacrol has strong antimicrobial effects in lab studies. One small trial found it comparable to antibiotics for SIBO, but the study was not well designed. Can irritate the stomach if not enteric-coated. Use cautiously.',dose:'600 mg/day emulsified or enteric-coated oregano oil for 6 weeks maximum; evidence weak for SIBO'},
{t:'t3',n:'Pearl powder',iN:true,tag:'Skin · Calcium · Anti-aging claims',e:1,s:4,r:1,o:1,c:1,d:5,desc:'Ground freshwater or seawater pearls used in traditional Chinese medicine for skin beauty and as a calcium source. Contains calcium carbonate, amino acids, and trace minerals. No human clinical trials support anti-aging or skin beauty claims from oral supplementation. Calcium content is real but there are far cheaper calcium sources available.',dose:'500–1,000 mg/day; no clinical evidence for beauty claims; expensive calcium source'},
{t:'t4',n:'Coltsfoot (Tussilago farfara)',iN:true,tag:'Pyrrolizidine alkaloids · Liver cancer',e:1,s:1,r:1,o:3,c:2,d:1,desc:'Contains pyrrolizidine alkaloids that are classified as confirmed liver carcinogens. These toxic compounds cause liver vein blockage and can lead to liver cancer with repeated exposure. Historically used for cough, but the cancer risk far outweighs any respiratory benefit. Banned or restricted as a food ingredient in multiple countries.',dose:'AVOID — contains hepatocarcinogenic pyrrolizidine alkaloids; banned in multiple countries'},
{t:'t4',n:'Chaparral (Larrea tridentata)',iN:true,tag:'Hepatotoxicity',e:1,s:1,r:1,o:2,c:2,d:1,desc:'A desert shrub marketed for "detox" and antioxidant benefits that carries serious liver damage risk. The FDA has received multiple reports of hepatitis, liver failure, and death associated with chaparral use. The active compound NDGA causes dose-dependent liver and kidney toxicity. No clinical benefit has been demonstrated in any human trial.',dose:'AVOID — FDA-warned hepatotoxicant; multiple cases of liver failure and death'},
{t:'t4',n:'Lobelia (Lobelia inflata)',iN:true,tag:'Respiratory · Emetic · Toxic',e:1,s:1,r:1,o:4,c:2,d:1,desc:'Sometimes called "Indian tobacco" and historically used for respiratory conditions, but the therapeutic dose is dangerously close to the toxic dose. Causes violent vomiting, respiratory depression, convulsions, and potentially coma at doses only slightly above those used medicinally. FDA classified it as a dangerous herb. No safe supplemental use exists.',dose:'AVOID — narrow therapeutic window; vomiting, respiratory depression, and convulsions at slightly elevated doses'},
{t:'t4',n:'Sassafras oil',iN:true,tag:'Safrole · Hepatocarcinogen',e:1,s:1,r:1,o:4,c:2,d:1,desc:'Contains safrole, which is classified as a confirmed liver carcinogen by international cancer authorities. Safrole is also a precursor chemical for the illegal drug MDMA. FDA banned safrole as a food additive in 1960. Despite this, sassafras tea and root bark products are still sold in some markets. There is no safe dose for internal consumption.',dose:'AVOID — safrole is a confirmed hepatocarcinogen; banned as a food additive since 1960'},
{t:'t4',n:'Ma huang (raw Ephedra herb)',iN:true,tag:'Cardiovascular death',e:2,s:1,r:2,o:5,c:2,d:1,desc:'The raw herbal form of ephedra, which contains variable and unpredictable amounts of the stimulant ephedrine. FDA banned ephedra supplements in 2004 after linking them to 155 deaths including heart attacks, strokes, and seizures. The raw herb is even more dangerous than standardised extracts because you cannot control the dose. Still sold in some markets.',dose:'AVOID — 155+ deaths documented; FDA banned in 2004; unpredictable ephedrine content'},
{t:'t4',n:'Methyl synephrine',iN:true,tag:'Cardiovascular · Arrhythmia',e:1,s:1,r:1,o:5,c:1,d:1,desc:'A potent synthetic stimulant found in some weight loss and pre-workout products that causes dangerous heart rhythm disturbances. More cardiotoxic than regular synephrine due to its enhanced ability to stimulate heart receptors. Multiple adverse cardiovascular events have been reported. Not a legitimate dietary ingredient by any regulatory standard.',dose:'AVOID — potent cardiovascular stimulant; causes arrhythmia and hypertensive crisis'},
{t:'t4',n:'Silver protein (mild silver protein)',iN:true,tag:'Argyria · No efficacy',e:1,s:1,r:1,o:3,c:1,d:3,desc:'A form of colloidal silver with larger particles that accumulate more readily in tissues, causing faster onset of argyria, the irreversible permanent blue-grey skin discolouration. No antimicrobial benefit when taken orally has been demonstrated. FDA says there is no safe or effective medical use for any silver-containing supplement taken by mouth.',dose:'AVOID — causes irreversible skin discolouration (argyria); no proven oral health benefit'},
{t:'t4',n:'Wormwood high-dose (Artemisia absinthium)',iN:true,tag:'Neurotoxicity · Thujone',e:2,s:1,r:1,o:4,c:3,d:1,desc:'Contains thujone, a compound that causes seizures, kidney failure, and brain damage at high doses. Low-dose wormwood is used short-term in some traditional protocols, but high-dose or long-term use is genuinely dangerous. The neurotoxic effects of thujone are well documented. Never exceed recommended doses or use for more than 4 weeks without supervision.',dose:'AVOID high doses; if used short-term, max 3 mg thujone/day for 4 weeks under supervision'},
{t:'t2',n:'Andrographis + Echinacea combo',iN:true,tag:'Cold/Flu · Immunity',e:3,s:4,r:2,o:4,c:3,d:4,desc:'This combination is used in several European cold and flu products and has been tested in a handful of randomised trials. Studies suggest it may reduce the duration and severity of upper respiratory symptoms when taken within the first 48 hours of illness. Neither herb alone is strongly supported, but the combination shows slightly better outcomes. Generally well tolerated for short-term use of one to two weeks.',dose:'Andrographis 400 mg + Echinacea 400 mg/day at first sign of cold; use for up to 10 days'},
{t:'t2',n:'Artichoke extract (Cynara scolymus)',iN:true,tag:'Liver · Digestion · Cholesterol',e:3,s:5,r:3,o:2,c:3,d:4,desc:'Artichoke leaf extract has moderate evidence for lowering LDL cholesterol and improving symptoms of indigestion. A 2018 Cochrane-style review found it reduced total cholesterol by roughly 10 to 15 percent in mildly elevated cases. It also stimulates bile production, which can ease bloating and discomfort after fatty meals. Very safe with minimal side effects in trials lasting up to 12 weeks.',dose:'600\u20131,800 mg/day standardised artichoke leaf extract, taken with meals'},
{t:'t3',n:'Astragaloside IV (isolated)',iN:true,tag:'Telomere · Anti-aging · Immunity',e:2,s:4,r:1,o:1,c:1,d:5,desc:'A purified compound from astragalus root that has been promoted as a telomerase activator and anti-aging supplement. Cell culture and animal studies show some telomere-related effects, but there are almost no published human clinical trials. It is extremely expensive in isolated form and the dose needed for any potential benefit in humans is unknown. Safety data from short-term studies is reassuring, but long-term human data is absent.',dose:'5\u201350 mg/day of isolated astragaloside IV; no established human clinical dose; very expensive'},
{t:'t2',n:'Berberine HCl (sustained release)',iN:true,tag:'Glucose · GI tolerability',e:4,s:3,r:2,o:2,c:2,d:3,desc:'Sustained-release berberine was developed to reduce the gastrointestinal side effects (cramping, diarrhea) common with standard berberine. Early studies suggest similar blood sugar lowering effects with fewer gut complaints. However, most of the clinical evidence still comes from standard immediate-release berberine. Sustained-release formulations are newer and more expensive, with fewer independent trials confirming their benefits.',dose:'500\u20131,000 mg/day sustained-release berberine HCl; fewer GI side effects than standard form'},
{t:'t2',n:'Bilberry extract',iN:true,tag:'Eye health · Circulation · Antioxidant',e:3,s:5,r:2,o:2,c:3,d:5,desc:'Bilberry is rich in anthocyanins and has been studied for eye fatigue, night vision, and circulatory health. Several small trials show modest improvements in visual fatigue from screen use and reduced eye dryness. The evidence for improving night vision is mixed and largely based on older studies. It is very safe with no significant drug interactions and has a long history of use in European herbal medicine.',dose:'80\u2013480 mg/day standardised to 25% anthocyanins; best studied for eye fatigue and dryness'},
{t:'t2',n:'Butyrate (calcium/magnesium)',iN:true,tag:'Gut barrier · IBD · Microbiome',e:3,s:4,r:2,o:3,c:3,d:5,desc:'Butyrate is a short-chain fatty acid naturally produced by gut bacteria when they ferment dietary fibre. Supplemental butyrate in calcium or magnesium salt form may support gut barrier integrity and reduce intestinal inflammation. Small clinical trials show benefit in ulcerative colitis and irritable bowel syndrome. It has an unpleasant smell but is generally well tolerated. Enteric-coated capsules are preferred for colonic delivery.',dose:'300\u20131,200 mg/day calcium or magnesium butyrate; enteric-coated for colonic delivery'},
{t:'t2',n:'Caralluma fimbriata',iN:true,tag:'Appetite · Weight management',e:2,s:4,r:2,o:2,c:3,d:5,desc:'A succulent plant traditionally eaten as a famine food in India that has been studied as an appetite suppressant. Two randomised controlled trials found modest reductions in waist circumference and hunger scores compared to placebo over 60 days. The weight loss effects were small and not consistently significant. It appears safe with no serious adverse events reported, but larger and longer trials are needed.',dose:'500\u20131,000 mg/day Caralluma fimbriata extract; modest appetite effects in small trials'},
{t:'t3',n:'Chrysin',iN:true,tag:'Aromatase inhibitor · Testosterone',e:2,s:3,r:1,o:2,c:3,d:3,desc:'A flavonoid found in passionflower and honey that shows aromatase-inhibiting effects in test tubes. However, chrysin is very poorly absorbed orally. Human studies show minimal to no effect on testosterone or estrogen levels at standard supplement doses. Despite strong marketing claims, the bioavailability problem means very little reaches the bloodstream. Not recommended as a testosterone booster based on current evidence.',dose:'500\u20132,000 mg/day; very poor oral bioavailability limits real-world effectiveness'},
{t:'t2',n:'Coleus forskohlii (Forskolin)',iN:true,tag:'cAMP · Thyroid · Weight',e:2,s:3,r:2,o:2,c:3,d:3,desc:'Forskolin activates the enzyme adenylate cyclase, which raises cyclic AMP levels in cells. A few small trials suggest it may help with body composition in overweight men and lower intraocular pressure in glaucoma patients. The evidence for weight loss is limited to one or two trials with small sample sizes. It can lower blood pressure and may interact with blood pressure medications and anticoagulants.',dose:'250 mg of 10% forskolin extract twice daily; limited evidence for weight loss'},
{t:'t3',n:'Emodin',iN:true,tag:'Gut motility · Anti-inflammatory',e:2,s:3,r:1,o:3,c:3,d:3,desc:'A naturally occurring anthraquinone found in rhubarb, aloe, and cascara that has laxative and anti-inflammatory effects. Animal studies show potential benefits for gut inflammation and metabolic health, but human clinical trials are very limited. At higher doses it can cause diarrhea, cramping, and electrolyte imbalances. Long-term use of anthraquinone laxatives has been linked to dependency and colonic changes.',dose:'20\u201350 mg/day emodin; use short-term only; laxative dependency risk with prolonged use'},
{t:'t2',n:'Gamma oryzanol',iN:true,tag:'Cholesterol · Menopause · Athletic',e:2,s:4,r:2,o:2,c:3,d:5,desc:'A mixture of compounds extracted from rice bran oil that has been studied for cholesterol reduction, menopausal hot flashes, and athletic performance. Japanese studies from the 1980s and 1990s showed modest cholesterol-lowering effects. A few trials found reduced hot flash severity in menopausal women. Claims about muscle-building effects are not supported by well-designed human studies. Generally very safe.',dose:'100\u2013600 mg/day gamma oryzanol from rice bran; modest cholesterol and menopause benefits'},
{t:'t2',n:'Gymnema sylvestre',iN:true,tag:'Blood sugar · Sugar cravings',e:3,s:4,r:2,o:2,c:3,d:3,desc:'An Ayurvedic herb known as the "sugar destroyer" because chewing the leaf temporarily blocks sweet taste on the tongue. Several clinical trials show it can lower fasting blood sugar and HbA1c in type 2 diabetics when used alongside standard treatment. It may also reduce sugar cravings. Can interact with diabetes medications by enhancing their effects, which could cause dangerously low blood sugar if not monitored.',dose:'400\u2013600 mg/day gymnemic acid extract; monitor blood sugar if taking diabetes medications'},
{t:'t2',n:'Hawthorn berry (Crataegus)',iN:true,tag:'Heart failure · Blood pressure',e:3,s:4,r:3,o:2,c:3,d:3,desc:'Hawthorn extract has been studied in multiple randomised trials for mild to moderate heart failure. A Cochrane review found it improved exercise tolerance and reduced symptoms like shortness of breath compared to placebo. The SPICE trial, the largest study, did not find a mortality benefit but confirmed symptomatic improvement. May interact with cardiac medications, so medical supervision is important.',dose:'160\u2013900 mg/day hawthorn extract standardised to flavonoids; use under medical supervision for heart conditions'},
{t:'t2',n:'Horse chestnut (Aesculus)',iN:true,tag:'Venous insufficiency · Leg swelling',e:3,s:3,r:3,o:2,c:3,d:3,desc:'Horse chestnut seed extract containing the active compound aescin is one of the best-studied herbal treatments for chronic venous insufficiency. A Cochrane review confirmed it reduces leg swelling and pain compared to placebo. It appears to work by reducing capillary permeability and improving venous tone. Raw horse chestnuts are toxic and must never be consumed. Only standardised extracts should be used.',dose:'300 mg twice daily standardised to 50 mg aescin; raw seeds are toxic and must never be eaten'},
{t:'t2',n:'Huperzine A',iN:true,tag:'Cognition · Acetylcholinesterase',e:3,s:3,r:2,o:4,c:3,d:3,desc:'A compound isolated from Chinese club moss that inhibits acetylcholinesterase, the enzyme that breaks down the neurotransmitter acetylcholine. Small Chinese trials reported improvements in memory and cognitive function in Alzheimer patients. It has a long half-life and can accumulate with daily use. Side effects include nausea, diarrhea, and slowed heart rate. Should not be combined with prescription cholinesterase inhibitors.',dose:'50\u2013200 mcg twice daily; do not combine with prescription cholinesterase inhibitors'},
{t:'t2',n:'Indole-3-Carbinol (I3C)',iN:true,tag:'Estrogen metabolism · Cancer prevention',e:2,s:3,r:2,o:2,c:3,d:3,desc:'A compound found in cruciferous vegetables that modifies estrogen metabolism, shifting it toward less potent forms. Some observational and early clinical studies suggest it may help with estrogen-sensitive conditions. I3C is unstable in the stomach and converts to DIM and other compounds, making its effects somewhat unpredictable. DIM supplements may offer more consistent results. Can interact with medications processed by liver enzymes.',dose:'200\u2013400 mg/day I3C; converts to DIM in the stomach; DIM may be more reliable'},
{t:'t2',n:'Larch arabinogalactan',iN:true,tag:'Prebiotic · Immunity · Fibre',e:2,s:5,r:2,o:3,c:3,d:5,desc:'A soluble dietary fibre extracted from larch trees that acts as a prebiotic, feeding beneficial gut bacteria and promoting butyrate production. Limited clinical studies suggest it may enhance immune function by increasing natural killer cell activity. It dissolves easily in water and is very well tolerated with minimal gas or bloating compared to other prebiotic fibres. More human research is needed to confirm immune benefits.',dose:'4\u201530 g/day dissolved in water; well-tolerated prebiotic fibre; immune claims need more research'},
{t:'t2',n:'Mastic gum (Pistacia lentiscus)',iN:true,tag:'H. pylori · GERD · Gut',e:3,s:4,r:2,o:3,c:2,d:5,desc:'A resin from the mastic tree used in Mediterranean traditional medicine for stomach problems. Clinical trials show it can kill Helicobacter pylori bacteria and improve symptoms of functional dyspepsia and acid reflux. One randomised trial found it healed duodenal ulcers at a rate comparable to antacids. It has anti-inflammatory and antimicrobial properties. The main downside is its relatively high cost compared to standard treatments.',dose:'350 mg three times daily for H. pylori and gastric complaints; take before meals'},
{t:'t2',n:'Meriva curcumin (phytosome)',iN:true,tag:'Joint · Inflammation · Bioavailable',e:3,s:4,r:3,o:2,c:2,d:4,desc:'Meriva is a patented curcumin formulation complexed with phosphatidylcholine to dramatically improve absorption. Clinical trials show it is roughly 29 times more bioavailable than standard curcumin. Studies in osteoarthritis patients found significant improvements in pain, stiffness, and physical function. It has been tested in more than 30 clinical studies with a good safety profile. More expensive than generic curcumin but backed by stronger clinical data.',dose:'500\u20131,000 mg/day Meriva curcumin phytosome (equivalent to about 200 mg curcuminoids)'},
{t:'t3',n:'Androsterone',iN:true,tag:'Hormone · Pheromone claims',e:1,s:2,r:1,o:3,c:1,d:2,desc:'A weak androgen metabolite of testosterone that is marketed as a prohormone and supposed pheromone. There is virtually no clinical evidence that supplementing with androsterone increases testosterone or has any meaningful hormonal effect when taken orally. Pheromone claims in humans are not supported by rigorous science. It is expensive and the hormonal classification means it may be banned in some sports and jurisdictions.',dose:'No established effective dose; not recommended; lacks clinical evidence for any claimed benefit'},
{t:'t3',n:'Avocado soybean unsaponifiables (ASU)',iN:true,tag:'Joint · OA',e:2,s:4,r:2,o:1,c:2,d:5,desc:'A mixture of compounds extracted from avocado and soybean oils that has been studied for knee and hip osteoarthritis. Several European trials found ASU reduced pain and improved function after three to six months of use. A large French trial showed it could reduce the need for anti-inflammatory drugs. Effects are slow to develop, typically taking two to three months. Widely prescribed in France but considered a supplement elsewhere.',dose:'300 mg/day ASU; effects take 2\u20133 months to appear; best studied for knee and hip OA'},
{t:'t3',n:'Bee pollen',iN:true,tag:'Energy · Immunity claims',e:1,s:3,r:1,o:3,c:3,d:4,desc:'Collected by honeybees from flower pollen and mixed with nectar and bee secretions. It contains proteins, vitamins, and minerals, but most health claims are not supported by clinical trials. A few small studies suggest possible antioxidant and anti-inflammatory effects. The main safety concern is severe allergic reactions, especially in people allergic to bee stings or pollen. Not recommended for allergy-prone individuals.',dose:'5\u201315 g/day bee pollen granules; serious allergy risk for sensitive individuals'},
{t:'t3',n:'Brewer\'s yeast',iN:true,tag:'B vitamins · Energy · Skin',e:2,s:4,r:2,o:3,c:4,d:5,desc:'Saccharomyces cerevisiae grown on malted barley, providing a natural source of B vitamins, chromium, and protein. Some evidence supports its use for blood sugar management in type 2 diabetes due to its chromium content. It may also help with acne due to its zinc and B vitamin content. It is inexpensive and widely available. People with yeast sensitivities or Crohn disease should avoid it.',dose:'1\u20132 tablespoons (15\u201330 g) daily; natural source of B vitamins and chromium'},
{t:'t3',n:'Calcium AEP (2-aminoethylphosphoric acid)',iN:true,tag:'Cell membrane · Multiple sclerosis claims',e:1,s:3,r:1,o:2,c:2,d:4,desc:'A form of calcium bound to 2-aminoethylphosphoric acid, promoted primarily by one physician in the mid-20th century for multiple sclerosis and other autoimmune conditions. The clinical evidence consists mainly of uncontrolled case reports and has never been replicated in randomised trials. Mainstream neurology does not recognise it as an MS treatment. It is generally safe at standard doses but unlikely to provide unique benefits.',dose:'500\u20131,500 mg/day calcium AEP; no quality clinical evidence for MS or autoimmune claims'},
{t:'t3',n:'Cetyl myristoleate',iN:true,tag:'Joint · Anti-inflammatory claims',e:1,s:4,r:1,o:2,c:2,d:5,desc:'A fatty acid ester originally discovered in mice that appeared resistant to arthritis. A couple of very small human studies reported improvements in joint function, but the trials were poorly designed and funded by supplement manufacturers. The mechanism of action is not well understood. It is generally safe but there is insufficient evidence to recommend it over better-studied joint supplements like glucosamine or curcumin.',dose:'350 mg/day cetyl myristoleate complex for 30 days; very limited human evidence'},
{t:'t3',n:'Coral calcium',iN:true,tag:'Bone · Alkaline claims',e:1,s:3,r:1,o:3,c:2,d:4,desc:'Calcium derived from fossilised coral, marketed with claims that it is superior to other calcium forms and can alkalise the body. The FTC and FDA took action against coral calcium marketers for making false cancer and disease cure claims. As a calcium source, it is no better absorbed than regular calcium carbonate. It may contain trace minerals but also carries a risk of lead contamination from oceanic sources.',dose:'500\u20131,000 mg/day as calcium; no better than standard calcium carbonate; contamination risk'},
{t:'t3',n:'DHEA topical cream',iN:true,tag:'Skin aging · Vaginal atrophy',e:2,s:3,r:2,o:2,c:2,d:2,desc:'Topical DHEA applied to the skin or vaginal mucosa has some clinical support for specific conditions. A large randomised trial found intravaginal DHEA effective for postmenopausal vaginal dryness and is now an FDA-approved prescription product (prasterone). Topical application for skin aging has weaker evidence. Systemic absorption can still affect hormone levels. Should be used under medical supervision, especially in hormone-sensitive conditions.',dose:'Vaginal: 6.5 mg/day intravaginal (prescription); topical skin: 1\u20132% cream; consult physician'},
{t:'t3',n:'Fenugreek + Ashwagandha stack',iN:true,tag:'Testosterone · Stress combo',e:2,s:3,r:1,o:2,c:2,d:3,desc:'A popular combination stack marketed for boosting testosterone and reducing cortisol in men. Both herbs individually have some evidence for their respective claims, but the combination has not been studied together in rigorous clinical trials. The rationale is theoretical. Fenugreek may cause a maple syrup smell in sweat and urine. Ashwagandha can affect thyroid hormone levels. Using both together increases the chance of side effects.',dose:'Fenugreek 500 mg + Ashwagandha (KSM-66) 600 mg/day; combination not clinically validated'},
{t:'t3',n:'Garcinia cambogia (HCA)',iN:true,tag:'Weight loss · Appetite',e:2,s:3,r:3,o:2,c:3,d:3,desc:'The rind of the Garcinia fruit contains hydroxycitric acid, which inhibits an enzyme involved in fat synthesis. Despite massive marketing, the largest and best-designed trials found minimal to no weight loss benefit over placebo. A 2011 meta-analysis found about 0.88 kg more weight loss than placebo, a clinically insignificant amount. FDA has warned about liver injury reports associated with some garcinia products. Not recommended for weight loss.',dose:'500\u20131,500 mg HCA three times daily before meals; minimal weight loss in clinical trials'},
{t:'t4',n:'Graviola (Annona muricata)',iN:true,tag:'Cancer claims · Neurotoxicity risk',e:1,s:2,r:1,o:2,c:2,d:3,desc:'A tropical fruit also called soursop that is aggressively marketed online as a cancer cure. While lab studies show certain compounds in graviola can kill cancer cells in test tubes, no human clinical trials have been conducted. The plant contains annonacin, a neurotoxin linked to atypical Parkinson disease in Caribbean populations who consume it regularly. The cancer cure claims are fraudulent and dangerous when they delay real treatment.',dose:'AVOID for cancer treatment; neurotoxin risk with regular use; no human clinical evidence'},
{t:'t3',n:'Hemp seed oil',iN:true,tag:'Omega fatty acids · Skin',e:2,s:5,r:1,o:3,c:4,d:5,desc:'Cold-pressed oil from hemp seeds that provides a favourable ratio of omega-6 to omega-3 fatty acids (roughly 3:1). It does not contain CBD or THC in meaningful amounts. Some small studies suggest benefits for eczema and dry skin when taken orally or applied topically. It is a reasonable plant-based source of essential fatty acids but not a substitute for EPA and DHA found in fish oil. Very safe with no drug interactions.',dose:'1\u20132 tablespoons/day or 1,000 mg capsules; does not replace EPA/DHA from fish oil'},
{t:'t3',n:'Horsetail (Equisetum)',iN:true,tag:'Hair · Nails · Silica',e:1,s:3,r:1,o:1,c:4,d:4,desc:'A prehistoric plant that is a natural source of silica, marketed for strengthening hair, nails, and bones. One small randomised trial found improved nail brittleness after 6 months. The evidence for hair growth is mostly anecdotal. Horsetail contains thiaminase, an enzyme that destroys vitamin B1, so long-term use can cause B1 deficiency. Products should be tested for thiaminase content. Not recommended for extended use without B1 supplementation.',dose:'300 mg/day standardised horsetail extract; supplement B1 if using long-term; limited evidence'},
{t:'t3',n:'Kelp (iodine-rich)',iN:true,tag:'Thyroid · Mineral · Contamination risk',e:2,s:2,r:1,o:3,c:4,d:3,desc:'Dried seaweed sold as a natural iodine source for thyroid support. The iodine content can vary enormously between batches, with some products containing dangerously high levels that can cause thyroid dysfunction. Heavy metal contamination (arsenic, lead, cadmium) is a documented concern with kelp products. People with existing thyroid conditions can experience serious flare-ups. A controlled iodine supplement is safer if iodine is genuinely needed.',dose:'150\u2013300 mcg iodine equivalent/day; variable iodine content makes dosing unreliable; contamination risk'},
{t:'t3',n:'L-Lysine',iN:true,tag:'Cold sores · Collagen · Immunity',e:2,s:5,r:2,o:3,c:4,d:5,desc:'An essential amino acid that has been studied primarily for preventing and treating cold sores caused by herpes simplex virus. The evidence is mixed, with some trials showing reduced recurrence and others showing no benefit. The theory is that lysine competes with arginine, which the virus needs to replicate. It also plays a role in collagen synthesis and calcium absorption. Very safe at standard doses with no significant side effects.',dose:'500\u20133,000 mg/day for cold sore prevention; take on empty stomach; avoid high-arginine foods during outbreaks'},
{t:'t3',n:'Melatonin gummies (high dose 5\u201310 mg)',iN:true,tag:'Overdosed · Sleep dependency',e:2,s:3,r:3,o:5,c:4,d:4,desc:'Many commercial melatonin gummies contain 5 to 10 mg per serving, which is far more than the 0.3 to 1 mg shown to be optimal in clinical research. Higher doses can cause morning grogginess, vivid nightmares, and may suppress natural melatonin production over time. A 2023 analysis found that many gummy products contained significantly more melatonin than listed on the label. Lower-dose melatonin (0.3 to 1 mg) is more effective and has fewer side effects.',dose:'Optimal dose is 0.3\u20131 mg 30\u201360 minutes before bed; most gummies are significantly overdosed'},
{t:'t3',n:'Noni juice (Morinda citrifolia)',iN:true,tag:'Immunity · Antioxidant claims',e:1,s:3,r:1,o:2,c:2,d:4,desc:'A tropical fruit juice marketed with broad health claims including immune support, cancer prevention, and pain relief. Most studies are small, poorly designed, or funded by noni juice companies. Antioxidant content exists but is not exceptional compared to common fruits. Several cases of liver toxicity have been reported in Europe, though causality is debated. Potential interaction with blood thinners due to vitamin K content.',dose:'30\u201360 mL/day noni juice; limited clinical evidence; liver toxicity cases reported'},
{t:'t4',n:'Comfrey root tea (internal)',iN:true,tag:'PA hepatotoxicity',e:1,s:1,r:1,o:3,c:2,d:1,desc:'Comfrey root taken internally contains high concentrations of pyrrolizidine alkaloids that cause veno-occlusive liver disease, a life-threatening condition where the small veins in the liver become blocked. Multiple countries have banned internal comfrey products. Even short-term ingestion has caused severe liver damage. Topical comfrey for muscle and joint pain is a different use case with much lower systemic absorption and better safety data.',dose:'AVOID internal use; pyrrolizidine alkaloids cause irreversible liver damage; external use only is safer'},
{t:'t4',n:'Foxglove (Digitalis purpurea)',iN:true,tag:'Cardiac glycoside · Fatal',e:1,s:1,r:2,o:5,c:1,d:1,desc:'The source plant for the heart drug digoxin, foxglove contains cardiac glycosides that can cause fatal heart rhythm disturbances at doses only slightly above those used therapeutically. It has an extremely narrow margin of safety. Multiple poisoning deaths occur each year from people mistaking it for a safe herbal tea or supplement. The pharmaceutical drug derived from it requires careful blood level monitoring. Never use the raw plant.',dose:'AVOID completely; contains cardiac glycosides that cause fatal arrhythmias; prescription digoxin requires blood monitoring'},
{t:'t4',n:'Hydrazine sulfate',iN:true,tag:'Cancer cachexia claims · Toxic',e:1,s:1,r:1,o:3,c:1,d:1,desc:'Promoted as a cancer treatment and weight-loss-prevention agent for cancer patients since the 1970s. Three large NCI-sponsored randomised controlled trials found no benefit for cancer cachexia and showed increased toxicity compared to placebo. It is a known hepatotoxin and neurotoxin. It has extremely dangerous interactions with common foods containing tyramine and with many medications. Use of hydrazine sulfate has contributed to patient deaths.',dose:'AVOID; NCI trials showed no cancer benefit plus increased toxicity; hepatotoxic and neurotoxic'},
{t:'t4',n:'Laetrile (amygdalin / vitamin B17)',iN:true,tag:'Cyanide · Cancer fraud',e:1,s:1,r:2,o:3,c:1,d:1,desc:'A compound derived from apricot kernels that was heavily promoted as a cancer cure in the 1970s and 1980s. It breaks down into hydrogen cyanide in the body. Multiple clinical trials found absolutely no anti-cancer benefit. The FDA banned it as a cancer treatment. Cyanide poisoning from laetrile has caused deaths. Despite being thoroughly debunked, it continues to be sold online and at alternative cancer clinics in some countries.',dose:'AVOID; releases hydrogen cyanide in the body; no anti-cancer benefit; deaths documented'},
{t:'t4',n:'Raw thyroid glandulars',iN:true,tag:'Thyrotoxicosis · Hormonal',e:1,s:1,r:1,o:4,c:2,d:1,desc:'Desiccated thyroid glands from animals (usually pigs or cattle) sold as dietary supplements. These products contain actual thyroid hormones (T3 and T4) in unpredictable amounts. Multiple cases of thyrotoxicosis (dangerously high thyroid hormone levels) have been reported from supplement use. Symptoms include rapid heartbeat, tremor, anxiety, and in severe cases, thyroid storm which can be fatal. Thyroid hormone should only be prescribed by a physician.',dose:'AVOID; contains unpredictable thyroid hormone levels; causes thyrotoxicosis; use only under medical prescription'},
{t:'t4',n:'Strychnine (nux vomica)',iN:true,tag:'Neurotoxin · Fatal seizures',e:1,s:1,r:1,o:5,c:1,d:1,desc:'Nux vomica seeds contain strychnine, one of the most potent convulsant poisons known. It causes uncontrollable muscle spasms and seizures that can lead to respiratory failure and death. Despite this, it is still found in some homeopathic and traditional medicine products, sometimes at concentrations high enough to cause poisoning. The lethal dose in humans is approximately 30 to 120 mg. There is absolutely no legitimate supplement use.',dose:'AVOID completely; strychnine causes fatal seizures; lethal dose is 30\u2013120 mg; no safe supplement use'},
];

